                                <span className="whitespace-normal break-words">{colId === 'status' ? <Activity size={12} className="text-slate-400" /> : COLUMN_LABELS[colId as string]}</span>
                                {sortConfig?.key === colId && (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-blue-600 ml-0.5" /> : <ArrowDown size={12} className="text-blue-600 ml-0.5" />)}
                            </div>
