    if (notesHeaderMatch) { if (flooringAcc) flushFlooringItem(); isNotesSection = true; currentSection = "General Notes"; const contentAfter = line.substring(notesHeaderMatch[0].length).trim(); if (contentAfter.length > 2) { const cleanedNote = cleanDescription(contentAfter); if (cleanedNote) notes.push(cleanedNote); } continue; }
    if (isNotesSection) {
        const isNewHeader = line.startsWith('#') || (CATEGORY_REGEX.test(line) && lineObj.rect && lineObj.rect[0] < LEFT_COLUMN_THRESHOLD) || /CONSTRUCTION\s+DETAILS|ERRORS\s+&\s+OMISSIONS/i.test(line);
        const isNoteSentence = /^(?:we\s+supplied|note|please|builder|site|attention|important)/i.test(line);
        const looksLikeTakeoffRow = DIMENSION_X_REGEX.test(line) && (SLASH_QTY_LEN_REGEX.test(line) || /qty|count/i.test(line));

