/**
 * Robust measurement of text width using Canvas API.
 * Adheres to requested Min (60px) / Max (520px) bounds.
 * Removed excess padding for shortest possible widths.
 */
const measureColumnWidth = (colKey: string, dataSample: ParsedLine[]): number => {
    if (colKey === 'status') return 50;

    const canvas = document.createElement("canvas");
    const context = canvas.getContext("2d");
    if (!context) return DEFAULT_WIDTHS[colKey] || 100;

    const bodyFont = "14px Arial, sans-serif"; 
    const headerFont = "600 10px Arial, sans-serif";

    // Requested Bounds
    const MIN_WIDTH = 40; // Lowered to allow even tighter columns if content is tiny
    const MAX_WIDTH = 520;
    const PADDING_X = 6; // Minimal 3px buffer on each side to prevent pixel-touching

    let maxWidth = MIN_WIDTH; 

    // 1. Measure Header
    // Headers need space for: text + sort icon (14) + drag handle (10) + auto-fit button (14)
    context.font = headerFont;
    const label = COLUMN_LABELS[colKey] || colKey;
    const headerTextWidth = context.measureText(label.toUpperCase()).width + 48; // Minimal icon footprint
    maxWidth = Math.max(maxWidth, headerTextWidth);

    // 2. Measure Cell Contents
    context.font = bodyFont;
    dataSample.forEach(row => {
        let text = '';
        const val = (row as any)[colKey];

        if (val === null || val === undefined) text = '';
        else if (colKey === 'total') text = (row.total?.toFixed(2) || '0.00');
        else if (colKey === 'price') text = '$' + (row.price?.toFixed(2) || '0.00') + ' /LM';
        else if (colKey === 'totalPrice') text = '$' + (row.totalPrice?.toFixed(2) || '0.00');
        else if (colKey === 'totalLm') text = (row.unit === 'L/M' && row.qty && row.length ? (row.qty * row.length).toFixed(2) : '--');
        else text = String(val);

        if (text) {
            const isBold = colKey === 'item' || colKey === 'spruceItemNo';
            if (isBold) context.font = "bold 14px Arial, sans-serif";
            else context.font = bodyFont;

            const width = context.measureText(text).width + PADDING_X; 
            if (width > maxWidth) maxWidth = width;
        }
    });

    return Math.min(maxWidth, MAX_WIDTH); 
};

const isSummaryRow = (row: ParsedLine): boolean => {
    const text = (row.item + " " + (row.description || "")).toLowerCase();
    return /total|summary|subtotal|sum\s+of/.test(text) && !/frame|truss|joist/.test(text.replace(/total/g, ''));
};

const DynamicInput = ({ 
  value, 
  onChange, 
  className,
  readOnly,
  autoFocus,
  onFocus,
  onBlur,
  onKeyDown,
  ...props
}: { 
  value: string; 
  onChange?: (e: React.ChangeEvent<HTMLTextAreaElement>) => void; 
  className: string;
  readOnly?: boolean;
  autoFocus?: boolean;
  onFocus?: () => void;
  onBlur?: (e: React.FocusEvent<HTMLTextAreaElement>) => void;
  onKeyDown?: (e: React.KeyboardEvent<HTMLTextAreaElement>) => void;
  [key: string]: any;
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  useEffect(() => {
      if (autoFocus && textareaRef.current) {
          textareaRef.current.focus();
          textareaRef.current.select();
      }
  }, [autoFocus]);
  return (
    <div className="relative w-full group min-h-[1.5rem] h-full flex items-center">
        <div className={`${className} invisible whitespace-normal break-words overflow-hidden h-auto absolute pointer-none`} aria-hidden="true">
            {value || ' '}
        </div>
        <textarea
            ref={textareaRef}
            value={value}
            onChange={onChange}
            onFocus={onFocus}
            onBlur={onBlur}
            onKeyDown={onKeyDown}
            className={`${className} w-full h-full resize-none overflow-hidden bg-transparent whitespace-normal break-words ${readOnly ? 'cursor-not-allowed opacity-70' : ''}`}
            readOnly={readOnly}
            rows={1}
            style={{ minHeight: '24px' }} 
            {...props}
        />
    </div>
  );
};

export interface CatalogDropdownProps {
    catalog: CatalogProduct[];
    onSelect: (product: CatalogProduct) => void;
    onClose: () => void;
    searchTerm: string;
    targetRef: React.RefObject<HTMLElement>;
    selectedIndex: number;
}

export const CatalogDropdown: React.FC<CatalogDropdownProps> = ({ catalog, onSelect, onClose, searchTerm, targetRef, selectedIndex }) => {
    const popupRef = useRef<HTMLDivElement>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const [style, setStyle] = useState<React.CSSProperties>({ visibility: 'hidden' });
    const MAX_HEIGHT = 320;

    const filtered = useMemo(() => {
        return getRelevanceSortedResults(catalog, searchTerm);
    }, [catalog, searchTerm]);

    const reposition = useCallback(() => {
        if (targetRef.current) {
            const rect = targetRef.current.getBoundingClientRect();
            const spaceBelow = window.innerHeight - rect.bottom;
            const spaceAbove = rect.top;
            const shouldFlip = spaceBelow < MAX_HEIGHT && spaceAbove > spaceBelow;

            setStyle({
                position: 'fixed',
                top: shouldFlip ? 'auto' : `${rect.bottom + 4}px`,
                bottom: shouldFlip ? `${window.innerHeight - rect.top + 4}px` : 'auto',
                left: `${rect.left}px`,
                width: `${Math.max(400, rect.width)}px`,
                zIndex: 9999,
                visibility: 'visible'
            });
        }
    }, [targetRef]);

    useEffect(() => {
        if (scrollRef.current && selectedIndex >= 0) {
            const container = scrollRef.current;
            const items = container.querySelectorAll('button');
            const target = items[selectedIndex] as HTMLElement;
            if (target) {
                const containerRect = container.getBoundingClientRect();
                const targetRect = target.getBoundingClientRect();
                if (targetRect.bottom > containerRect.bottom) {
                    target.scrollIntoView({ block: 'end', behavior: 'smooth' });
                } else if (targetRect.top < containerRect.top) {
                    target.scrollIntoView({ block: 'start', behavior: 'smooth' });
                }
            }
        }
    }, [selectedIndex]);

    useEffect(() => {
        reposition();
        const handleScroll = () => reposition();
        const handleResize = () => reposition();
        window.addEventListener('scroll', handleScroll, true);
        window.addEventListener('resize', handleResize);
        return () => {
            window.removeEventListener('scroll', handleScroll, true);
            window.removeEventListener('resize', handleResize);
        };
    }, [reposition, searchTerm]);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (popupRef.current && !popupRef.current.contains(e.target as Node)) onClose();
        };
        const timer = setTimeout(() => document.addEventListener('mousedown', handleClickOutside), 10);
        return () => { clearTimeout(timer); document.removeEventListener('mousedown', handleClickOutside); };
    }, [onClose]);

    if (!searchTerm || searchTerm.length < 2) return null;

    const content = (
        <div 
            ref={popupRef} 
            style={style} 
            className="bg-white dark:bg-slate-800 rounded-xl shadow-[0_10px_50px_-10px_rgba(0,0,0,0.3)] border border-slate-200 dark:border-slate-700 overflow-hidden animate-in fade-in slide-in-from-top-1 duration-150"
            /* Fix: Changed non-existent 'onVerticalScroll' to 'onScroll' to prevent TypeScript error */
            onScroll={(e) => e.stopPropagation()}
        >
            <div className="px-3 py-2 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 flex items-center justify-between">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest flex items-center gap-1.5">
                    <Database size={10} className="text-blue-500" /> ERP Catalog Suggestions
                </span>
                <span className="text-[9px] text-slate-400 font-bold">{filtered.length} matches</span>
            </div>
            <div ref={scrollRef} className="max-h-[300px] overflow-y-auto overflow-x-hidden custom-scrollbar overscroll-contain">
                {filtered.length === 0 ? (
                    <div className="p-6 text-center text-slate-400 italic text-xs">No catalog matches found.</div>
                ) : (
                    <div className="divide-y divide-slate-50 dark:divide-slate-700/50">
                        {filtered.map((p, idx) => (
                            <button 
                                key={p.itemNo} 
                                type="button"
                                onMouseDown={(e) => { 
                                    e.preventDefault(); 
                                    e.stopPropagation();
                                    onSelect(p); 
                                    onClose(); 
                                }} 
                                className={`w-full text-left p-3 transition-all flex flex-col gap-0.5 group ${
                                    selectedIndex === idx 
                                    ? 'bg-blue-600 shadow-inner' 
                                    : 'hover:bg-blue-50 dark:hover:bg-blue-900/30'
                                }`}
                            >
                                <div className="flex items-center justify-between gap-2">
                                    <span className={`text-xs font-black uppercase tracking-tight ${selectedIndex === idx ? 'text-white' : 'text-blue-600 dark:text-blue-400'}`}>
                                        {p.itemNo}
                                    </span>
                                    <span className={`text-[10px] font-black uppercase ${selectedIndex === idx ? 'text-blue-200' : 'text-slate-400'}`}>
                                        {p.unit || ''}
                                    </span>
                                </div>
                                <div className={`text-sm font-medium whitespace-normal break-words ${selectedIndex === idx ? 'text-white' : 'text-slate-700 dark:text-slate-200'}`}>
                                    {p.description}
                                </div>
                                <div className="flex justify-between items-center mt-1">
                                    <div className={`text-[10px] font-bold flex gap-2 ${selectedIndex === idx ? 'text-blue-100' : 'text-slate-400'}`}>
                                        {p.dimensions && <span>{p.dimensions}</span>}
                                        {p.grade && <span>• {p.grade}</span>}
                                    </div>
                                    <div className={`text-xs font-black flex items-center gap-0.5 ${selectedIndex === idx ? 'text-white' : 'text-emerald-600 dark:text-emerald-400'}`}>
                                        <DollarSign size={10} />
                                        {((p.priceCents || 0) / 100).toFixed(2)}
                                    </div>
                                </div>
                            </button>
                        ))}
                    </div>
                )}
            </div>
            <div className="px-3 py-1.5 border-t border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 flex items-center justify-between text-[9px] text-slate-400 font-bold uppercase tracking-tighter">
                <div className="flex items-center gap-2">
                    <span className="flex items-center gap-1 bg-slate-200 dark:bg-slate-700 px-1 rounded">↑↓</span> to move
                </div>
                <div className="flex items-center gap-2">
                    <span className="flex items-center gap-1 bg-slate-200 dark:bg-slate-700 px-1 rounded">Enter</span> to select
                </div>
            </div>
        </div>
    );

    return createPortal(content, document.body);
};

interface TableRowProps {
  row: ParsedLine;
  onUpdateRow: (id: string, field: keyof ParsedLine, value: any) => void;
  visibleColumns: (keyof ParsedLine | 'status' | 'totalLm')[];
  isActive: boolean;
  onClick: () => void;
  onDelete?: () => void;
  isSelected: boolean;
  onToggleSelect: (id: string) => void;
  hasMultipleSources: boolean;
  onTeach?: (row: ParsedLine) => void;
  onInspect?: (row: ParsedLine) => void;
  isSummary?: boolean;
  validationMessages?: string[];
  onOpenMoveMenu?: () => void;
  onOpenCatalogLookup: (rowId: string, field: 'spruceItemNo' | 'spruceDescription', ref: React.RefObject<HTMLTableCellElement>, currentVal: string) => void;
  onNavigate: (e: React.KeyboardEvent, direction: 'up' | 'down' | 'left' | 'right' | 'enter', columnKey: string) => void;
  catalog: CatalogProduct[];
  uiPreferences?: UiPreferences;
  isCommittingRef: React.RefObject<boolean>;
  isLookupOpen: boolean;
}

// Added comment to address lint error: Explicitly using React.memo to ensure it refers to the imported React module.
const TableRow = React.memo<TableRowProps>(({
  row,
  onUpdateRow,
  visibleColumns,
  isActive,
  onClick,
  onDelete,
  isSelected,
  onToggleSelect,
  hasMultipleSources,
  onTeach,
  onInspect,
  isSummary,
  validationMessages,
  onOpenMoveMenu,
  onOpenCatalogLookup,
  onNavigate,
  catalog,
  uiPreferences,
  isCommittingRef,
  isLookupOpen
}) => {
  const rowRef = useRef<HTMLTableRowElement>(null);
  const spruceItemRef = useRef<HTMLTableCellElement>(null);
  const spruceDescRef = useRef<HTMLTableCellElement>(null);

  const rowLatestRef = useRef(row);
  useEffect(() => { rowLatestRef.current = row; }, [row]);

  useEffect(() => {
    if (isActive && rowRef.current && document.activeElement?.closest('tr') !== rowRef.current) {
        rowRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [isActive]);

  const handleKeyDown = (e: React.KeyboardEvent, key: string) => {
    if (isLookupOpen && (key === 'spruceItemNo' || key === 'spruceDescription')) {
        if (['ArrowUp', 'ArrowDown', 'Enter'].includes(e.key)) return;
    }

    const isTextarea = e.currentTarget.tagName === 'TEXTAREA';
    const selectionStart = (e.currentTarget as any).selectionStart;
    const selectionEnd = (e.currentTarget as any).selectionEnd;
    const textLength = (e.currentTarget as any).value.length;

    if (e.key === 'ArrowUp') onNavigate(e, 'up', key);
    else if (e.key === 'ArrowDown') onNavigate(e, 'down', key);
    else if (e.key === 'ArrowLeft') { if (!isTextarea || selectionStart === 0) onNavigate(e, 'left', key); }
    else if (e.key === 'ArrowRight') { if (!isTextarea || selectionEnd === textLength) onNavigate(e, 'right', key); }
    else if (e.key === 'Enter') onNavigate(e, 'enter', key);
  };

  const handleSpruceFocus = (field: 'spruceItemNo' | 'spruceDescription', ref: React.RefObject<HTMLTableCellElement>, val: string) => {
      onClick();
      onOpenCatalogLookup(row.id, field, ref, val);
  };

  const handleBlur = (field: 'spruceItemNo' | 'spruceDescription') => {
    setTimeout(() => {
        if (!isCommittingRef.current) {
            onOpenCatalogLookup(row.id, field, { current: null } as any, ""); 
        }
    }, 150);
  };

  const renderCellContent = (key: keyof ParsedLine | 'totalLm', row: ParsedLine, onUpdate: (id: string, field: keyof ParsedLine, value: any) => void, isActive: boolean) => {
    const commonClasses = "cell-input w-full bg-white/50 dark:bg-slate-900/50 border border-transparent hover:border-slate-200 dark:hover:border-slate-700 rounded px-1 py-0.5 outline-none text-sm text-slate-700 dark:text-slate-100 placeholder:text-slate-300 dark:placeholder:text-slate-600 focus:bg-white dark:focus:bg-slate-900 focus:ring-2 focus:ring-blue-500/50 focus:border-blue-400 dark:focus:border-blue-500 transition-all duration-200 leading-relaxed text-left";
    const isLocked = row.locked;
    const finalClasses = isLocked ? `${commonClasses} bg-transparent text-slate-500 cursor-not-allowed border-none` : commonClasses;

    switch (key) {
        case 'item':
            const filteredNotes = (row.parsingNotes || []).filter(n => 
                !n.includes('Source:') && 
                n !== 'Auto-Detected Split' && 
                !n.includes('mapped to Spruce') && 
                !n.toLowerCase().includes('auto-mapped') && 
                !n.includes('LM_FALLBACK') &&
                !n.includes('CODE_EXACT') &&
                !n.includes('MEMORY') &&
                !n.includes('RULE_BRACING') &&
                !n.startsWith('Mapped from')
            );
            return (
                 <div className="flex flex-col w-full h-full justify-center">
                    <div className="flex flex-wrap items-center gap-2">
                        <div className="flex-1 min-w-0">
                            <DynamicInput value={row.item} onChange={(e) => onUpdate(row.id, 'item', e.target.value)} onKeyDown={(e) => handleKeyDown(e, 'item')} onFocus={onClick} data-col-key="item" data-row-id={row.id} className={`${finalClasses} font-medium whitespace-normal break-words`} autoFocus={row.isNew && isActive} readOnly={isLocked} />
                        </div>
                    </div>
                    {filteredNotes.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1 animate-in fade-in zoom-in-95">
                            {filteredNotes.map((note, i) => (
                                <span key={i} className="text-[10px] bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 px-1.5 py-0 rounded-full flex items-center gap-1 border border-amber-100 dark:border-amber-800/50 whitespace-normal break-words"><AlertCircle size={8} />{note}</span>
                            ))}
                        </div>
                    )}
                 </div>
            );
        case 'spruceItemNo':
            return (
                <div className="relative group/spruce">
                    <DynamicInput value={row.spruceItemNo || ''} onFocus={() => handleSpruceFocus('spruceItemNo', spruceItemRef, row.spruceItemNo || '')} onBlur={() => handleBlur('spruceItemNo')} onKeyDown={(e) => handleKeyDown(e, 'spruceItemNo')} data-col-key="spruceItemNo" data-row-id={row.id} onChange={(e) => { onUpdate(row.id, 'spruceItemNo', e.target.value); onOpenCatalogLookup(row.id, 'spruceItemNo', spruceItemRef, e.target.value); }} className={`${finalClasses} text-xs whitespace-normal break-all ${row.spruceMapped ? 'text-blue-600 dark:text-blue-400 font-bold' : 'text-slate-700 dark:text-slate-200'}`} placeholder="Search Code..." readOnly={isLocked} />
                    {row.spruceMapped && <div className="absolute -right-1 -top-1"><CheckCircle size={10} className="text-blue-500 bg-white dark:bg-slate-900 rounded-full" /></div>}
                </div>
            );
        case 'spruceDescription':
            return (
                <div className="relative">
                    <DynamicInput value={row.spruceDescription || ''} onFocus={() => handleSpruceFocus('spruceDescription', spruceDescRef, row.spruceDescription || '')} onBlur={() => handleBlur('spruceDescription')} onKeyDown={(e) => handleKeyDown(e, 'spruceDescription')} data-col-key="spruceDescription" data-row-id={row.id} onChange={(e) => { onUpdate(row.id, 'spruceDescription', e.target.value); onOpenCatalogLookup(row.id, 'spruceDescription', spruceDescRef, e.target.value); }} className={`${finalClasses} text-xs whitespace-normal break-words ${row.spruceMapped ? 'text-blue-700 dark:text-blue-300 font-medium italic' : 'text-slate-700 dark:text-slate-200'}`} placeholder="Catalog Search..." readOnly={isLocked} />
                </div>
            );
        case 'spruceGroup':
            return (
                <div className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase py-1 flex items-start gap-1 whitespace-normal break-words text-left">
                    {row.spruceGroup && <Tag size={10} className="opacity-50 mt-0.5 shrink-0" />}
                    {row.spruceGroup || ''}
                </div>
            );
        case 'spruceSection':
            return (
                <div className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase py-1 flex items-start gap-1 whitespace-normal break-words text-left">
                    {row.spruceSection && <Layers size={10} className="opacity-50 mt-0.5 shrink-0" />}
                    {row.spruceSection || ''}
                </div>
            );
        case 'description': return <DynamicInput value={row.description || ''} onChange={(e) => onUpdate(row.id, 'description', e.target.value)} onKeyDown={(e) => handleKeyDown(e, 'description')} onFocus={onClick} data-col-key="description" data-row-id={row.id} className={`${finalClasses} whitespace-normal break-words`} readOnly={isLocked} />;
        case 'qty': return <input type="number" value={row.qty} onChange={(e) => onUpdate(row.id, 'qty', e.target.value)} onKeyDown={(e) => handleKeyDown(e, 'qty')} onFocus={onClick} data-col-key="qty" data-row-id={row.id} className={`${finalClasses} cell-input no-spinner text-left font-bold text-blue-600 dark:text-blue-400`} readOnly={isLocked} />;
        case 'length': return <input type="number" value={row.length || ''} onChange={(e) => onUpdate(row.id, 'length', e.target.value)} onKeyDown={(e) => handleKeyDown(e, 'length')} onFocus={onClick} data-col-key="length" data-row-id={row.id} className={`${finalClasses} cell-input no-spinner text-left ${!row.length ? 'opacity-30 dark:opacity-40' : ''}`} placeholder="-" readOnly={isLocked} />;
        case 'totalLm':
            return (
                <div className="text-left font-mono text-slate-500 flex items-center justify-start h-full px-1 py-0.5">
                    {row.unit === 'L/M' && row.qty && row.length 
                        ? (row.qty * row.length).toFixed(2) 
                        : <span className="opacity-20 text-slate-400 font-sans">–</span>}
                </div>
            );
        case 'unit': return (
                <div className="relative h-full flex items-center">
                    <select value={row.unit} onChange={(e) => onUpdate(row.id, 'unit', e.target.value)} onKeyDown={(e) => handleKeyDown(e, 'unit')} onFocus={onClick} data-col-key="unit" data-row-id={row.id} className={`${finalClasses} cell-input appearance-none cursor-pointer font-medium text-xs w-full text-left`} disabled={isLocked}>
                        <option value="L/M">L/M</option>
                        <option value="EA">EA</option>
                        <option value="m2">m2</option>
                    </select>
                </div>
            );
        case 'price': return (
            <div className="text-left text-emerald-600 dark:text-emerald-400 whitespace-nowrap flex items-center justify-start h-full px-1 py-0.5 leading-relaxed">
                <span className="text-[10px] opacity-50 mr-0.5">$</span>
                {(row.price || 0).toFixed(2)}
                <span className="text-[9px] opacity-40 ml-1 text-slate-500 font-medium">/{row.unit === 'L/M' ? 'LM' : row.unit === 'm2' ? 'm2' : 'EA'}</span>
            </div>
        );
        case 'total': return <div className="text-left font-bold text-slate-800 dark:text-slate-100 whitespace-nowrap flex items-center justify-start h-full px-1">{row.total?.toFixed(2) || '0.00'}</div>;
        case 'totalPrice': return (
            <div 
                className="text-left font-bold text-emerald-700 dark:text-emerald-400 whitespace-nowrap flex items-center justify-start h-full px-1 py-0.5 leading-relaxed"
                title={row.unit === 'L/M' ? `Total = $/LM × (Qty ${row.qty} × Len ${row.length})` : undefined}
            >
                <span className="text-[10px] opacity-50 mr-0.5">$</span>
                {(row.totalPrice || 0).toFixed(2)}
            </div>
        );
        case 'dimensions': 
            const takeoffDim = normalizeDimensions(row.dimensions);
            const catalogDim = normalizeDimensions(row.spruceDescription || '');
            let isMismatch = false;

            if (row.spruceMapped && row.spruceItemNo !== 'PIDRRDM') {
                const prod = catalog.find(p => p.itemNo === row.spruceItemNo);
                const currentLineSheetDims = parseSheetDimsFromLine(row.dimensions);

                if (prod && prod.sheetDimsMm && currentLineSheetDims) {
                    const match = sheetDimsMatch(currentLineSheetDims, prod.sheetDimsMm);
                    isMismatch = !match.ok;
                } else {
                    isMismatch = takeoffDim && catalogDim && !catalogDim.includes(takeoffDim);
                }
            }

            return (
                <div className="relative flex items-center gap-1 group/dim">
                    <DynamicInput 
                        value={row.dimensions} 
                        onChange={(e) => onUpdateRow(row.id, 'dimensions', e.target.value)} 
                        onKeyDown={(e) => handleKeyDown(e, 'dimensions')} 
                        onFocus={onClick} 
                        data-col-key="dimensions" 
                        data-row-id={row.id} 
                        className={`${finalClasses} text-xs whitespace-normal break-all text-left ${isMismatch ? 'text-red-600 dark:text-red-400 ring-1 ring-red-500/50' : ''}`} 
                        readOnly={isLocked} 
                    />
                    {isMismatch && (
                        <div className="shrink-0 text-red-500" title="Dimension mismatch: Interpreted sheet size differs significantly from ERP catalog data.">
                            <AlertTriangle size={12} />
                        </div>
                    )}
                </div>
            );
        case 'grade':
        case 'section':
        case 'subSection': return <DynamicInput value={row[key as keyof ParsedLine] as string || ''} onChange={(e) => onUpdateRow(row.id, key as keyof ParsedLine, e.target.value)} onKeyDown={(e) => handleKeyDown(e, key as keyof ParsedLine)} onFocus={onClick} data-col-key="key" data-row-id={row.id} className={`${finalClasses} whitespace-normal break-words text-left ${key === 'section' ? 'font-semibold text-slate-600 dark:text-slate-200' : ''} ${key === 'subSection' ? 'text-slate-600 dark:text-slate-200' : ''}`} readOnly={isLocked} />;
        default: return <span className="text-slate-400 italic">N/A</span>;
    }
  };

  return (
    <tr ref={rowRef} className={`group border-b border-slate-100 dark:border-slate-800 transition-all duration-200 ease-out ${isActive ? 'bg-blue-50/80 dark:bg-blue-900/20 shadow-[inset_3px_0_0_0] shadow-blue-500 z-10 relative' : isSelected ? 'bg-blue-50/40 dark:bg-blue-900/10' : row.locked ? 'bg-slate-50/50 dark:bg-slate-900/50' : isSummary ? 'bg-amber-50/50 dark:bg-amber-900/10' : 'hover:bg-slate-50 dark:hover:bg-slate-800/40'}`} onClick={onClick}>
        <td className="px-1 py-1.5 border-r border-slate-100 dark:border-slate-800 align-top w-6" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center justify-center pt-1.5">
                <button onClick={() => onToggleSelect(row.id)} className={`transition-all duration-200 transform active:scale-90 ${isSelected ? 'text-blue-600 dark:text-blue-400' : 'text-slate-300 dark:text-slate-600 hover:text-slate-500'}`}>{isSelected ? <CheckSquare size={14} /> : <Square size={14} />}</button>
            </div>
        </td>
        {visibleColumns.map(colKey => {
            if (colKey === 'status') {
                 return (
                    <td key={colKey} className="px-1 py-1.5 border-r border-slate-100 dark:border-slate-800 text-left align-top relative w-8">
                        <div className="flex flex-col items-start gap-1 pt-2 group/status">
                            {row.locked ? <div title="Group Locked"><Lock size={12} className="text-slate-400" /></div> : isSummary ? <div title="Stated Total / Summary Line"><Calculator size={12} className="text-amber-500" /></div> : (
                                <div className="relative group/status-dot flex flex-col items-start gap-1.5">
                                    <div className={`w-2 h-2 rounded-full cursor-help transition-transform duration-300 ${(row.confidence || 0) > 0.8 ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]' : (row.confidence || 0) > 0.5 ? 'bg-amber-500' : 'bg-red-500'}`} />
                                    <div className="absolute left-full top-1/2 -translate-y-1/2 ml-3 hidden group-hover/status-dot:block z-[100] animate-in fade-in slide-in-from-left-1 duration-150 pointer-events-none">
                                        <div className="bg-slate-900 text-white text-[11px] px-3 py-2 rounded-lg shadow-xl border border-slate-700 min-w-[180px] max-w-[240px] leading-relaxed relative">
                                            <div className="absolute right-full top-1/2 -translate-y-1/2 w-0 h-0 border-y-[6px] border-y-transparent border-r-[6px] border-r-slate-900"></div>
                                            <div className="flex flex-col gap-1">
                                                <span className="font-bold text-slate-400 uppercase text-[9px] tracking-widest border-b border-slate-800 pb-1 mb-1">Mapping Insight</span>
                                                <span className="font-medium whitespace-normal break-words">{row.matchReason || (row.spruceMapped ? "Matched, no reason available." : "No match found.")}</span>
                                                {row.confidence !== undefined && (
                                                    <span className="text-[9px] text-slate-500 mt-1 italic">Parser Confidence: {Math.round(row.confidence * 100)}%</span>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </td>
                 );
            }
            return <td key={colKey} ref={colKey === 'spruceItemNo' ? spruceItemRef : colKey === 'spruceDescription' ? spruceDescRef : null} className="px-1 py-1.5 border-r border-slate-100 dark:border-slate-800 align-top overflow-hidden text-left">{renderCellContent(colKey, row, onUpdateRow, isActive)}</td>;
        })}
        <td className="px-1 py-1.5 text-left align-top w-12 relative">
             {!row.locked && (
                 <div className="flex items-center justify-start gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity duration-200 pt-1">
                    {onOpenMoveMenu && <button onClick={(e) => { e.stopPropagation(); onOpenMoveMenu(); }} className="p-0.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded transition-colors" title="Move to Group"><ArrowRightLeft size={12} /></button>}
                    {onInspect && <button onClick={(e) => { e.stopPropagation(); onInspect(row); }} className="p-0.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded transition-colors" title="Inspect Parsing Logic"><Search size={12} /></button>}
                    {onDelete && <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="p-0.5 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 rounded transition-colors" title="Delete Row"><Trash2 size={12} /></button>}
                 </div>
             )}
        </td>
    </tr>
  );
});

export const PreviewTable: React.FC<PreviewTableProps> = ({ 
  allData, data, onUpdateRow, activeRowId, onRowClick, catalog = [], onAddRow, onDeleteRow, onBulkUpdate, onBulkDelete, onTeach, onInspect, onExport, onReview, onEditSection, validationResult, validationIssues = 0, uiPreferences, onAddDraftLines,
  onResetView, onTotalWidthReport, pineWastagePct, savedColumnWidths, onSaveColumnWidths, onReparse, isReparsing
}) => {
  const [filterText, setFilterText] = useState('');
  const [showOnlyUnmapped, setShowOnlyUnmapped] = useState(false);
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [selectedItems, setSelectedItems] = useState<Set<string>>(new Set());
  const [isGrouped, setIsGrouped] = useState(true);
  const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());
  const [columnOrder, setColumnOrder] = useState<(keyof ParsedLine | 'status' | 'totalLm')[]>(DEFAULT_ORDER);
  const [hiddenColumns, setHiddenColumns] = useState<Set<string>>(new Set(['description', 'section', 'spruceGroup', 'spruceSection'])); 
  const [userTouchedGroupVisibility, setUserTouchedGroupVisibility] = useState(false); // Flag to track manual overrides
  const [showColumnMenu, setShowColumnMenu] = useState(false);
  const [moveMenuRowId, setMoveMenuRowId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);
  const [bulkMenuMode, setBulkMenuMode] = useState<'none' | 'move' | 'edit'>('none');
  const [bulkEditField, setBulkEditField] = useState<keyof ParsedLine | ''>('');
  const [bulkEditValue, setBulkEditValue] = useState<string>('');
  const [catalogLookup, setCatalogLookup] = useState<{ rowId: string; field: 'spruceItemNo' | 'spruceDescription'; targetRef: React.RefObject<HTMLTableCellElement>; searchTerm: string; } | null>(null);
  const [dropdownSelectedIndex, setDropdownSelectedIndex] = useState(-1);
  const [showPineWastage, setshowPineWastage] = useState(false);
  const [hasSavedWidths, setHasSavedWidths] = useState(!!savedColumnWidths && Object.keys(savedColumnWidths).length > 0);

  const lastWidthReported = useRef(0);
  const [columnWidths, setColumnWidths] = useState<Record<string, number>>(() => {
      const widths = { ...DEFAULT_WIDTHS, ...(savedColumnWidths || {}) };
      widths.status = 50;
      return widths;
  });
  const resizingRef = useRef<{ col: string; startX: number; startWidth: number } | null>(null);
  const [deleteCandidateId, setDeleteCandidateId] = useState<string | null>(null);
  const [showBulkDeleteConfirm, setshowBulkDeleteConfirm] = useState(false);
  const isCommittingRef = useRef(false);

  const mappingStats = useMemo(() => {
      const total = allData.length;
      if (total === 0) return { count: 0, percent: 0 };
      const mapped = allData.filter(r => r.spruceMapped).length;
      return { count: mapped, percent: Math.round((mapped / total) * 100) };
  }, [allData]);

  const visibleColumns = useMemo(() => columnOrder.filter(col => !hiddenColumns.has(col)), [columnOrder, hiddenColumns]);

  const processedData = useMemo(() => {
    let result = data;
    if (showOnlyUnmapped) result = result.filter(row => !row.spruceMapped);
    if (filterText) {
      const low = filterText.toLowerCase();
      result = result.filter(row => row.item.toLowerCase().includes(low) || row.section.toLowerCase().includes(low) || row.subSection.toLowerCase().includes(low) || row.dimensions.toLowerCase().includes(low) || row.grade.toLowerCase().includes(low) || (row.spruceItemNo && row.spruceItemNo.toLowerCase().includes(low)) || (row.spruceDescription && row.spruceDescription.toLowerCase().includes(low)) || (row.description && row.description.toLowerCase().includes(low)));
    }
    if (sortConfig) {
      result = [...result].sort((a, b) => {
        const getValue = (item: ParsedLine) => {
            if (sortConfig.key === 'status') return (item.confidence ?? 0);
            if (sortConfig.key === 'totalLm') return item.unit === 'L/M' ? item.total : 0;
            return item[sortConfig.key as keyof ParsedLine];
        };
        const aValue = getValue(a);
        const bValue = getValue(b);
        if (aValue === null && bValue === null) return 0;
        if (aValue === null) return 1;
        if (bValue === null) return -1;
        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return result;
  }, [data, filterText, sortConfig, showOnlyUnmapped]);

  /**
   * Auto fits a single target column based on visible data.
   */
  const handleAutoFitColumn = useCallback((colKey: string) => {
      // Use processedData (visible filtered/sorted rows) for measurement
      const newWidth = measureColumnWidth(colKey, processedData.slice(0, 200));
      setColumnWidths(prev => ({ ...prev, [colKey]: newWidth }));
      setHasSavedWidths(true);
  }, [processedData]);

  /**
   * Auto fits all currently visible columns.
   */
  const handleAutoFitAll = useCallback(() => {
      const newWidths = { ...columnWidths };
      const sample = processedData.slice(0, 200);

      visibleColumns.forEach(col => {
          newWidths[col as string] = measureColumnWidth(col as string, sample);
      });

      setColumnWidths(newWidths);
      setHasSavedWidths(true);
  }, [processedData, visibleColumns, columnWidths]);

  // CONTENT-AWARE AUTO COLUMN WIDTHS (Initial only if no saved widths)
  useEffect(() => {
      if (allData.length > 0 && !hasSavedWidths) {
          handleAutoFitAll();
      }
  }, [allData.length > 0 && !hasSavedWidths]); // Run once when data loads if not overridden

  // AUTO TOGGLE GROUP COLUMN VISIBILITY
  useEffect(() => {
      if (userTouchedGroupVisibility) return;

      setHiddenColumns(prev => {
          const next = new Set(prev);
          if (isGrouped) {
              next.add('section'); // Key for Group column is 'section'
          } else {
              next.delete('section');
          }
          return next;
      });
  }, [isGrouped, userTouchedGroupVisibility]);

  // TOTAL REQUIRED WIDTH REPORTING
  useEffect(() => {
      if (onTotalWidthReport) {
          // Calculate total width including selection column, columns, and actions column (20px each side)
          const totalWidth = visibleColumns.reduce((sum, col) => sum + (columnWidths[col as string] || 100), 20 + 60);
          if (totalWidth !== lastWidthReported.current) {
              onTotalWidthReport(totalWidth);
              lastWidthReported.current = totalWidth;
          }
      }
  }, [columnWidths, visibleColumns, onTotalWidthReport]);

  const lookupFilteredCatalog = useMemo(() => {
    return getRelevanceSortedResults(catalog, catalogLookup?.searchTerm || '');
  }, [catalog, catalogLookup?.searchTerm]);

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
        if (!catalogLookup) return;

        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setDropdownSelectedIndex(prev => (prev < lookupFilteredCatalog.length - 1 ? prev + 1 : prev));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setDropdownSelectedIndex(prev => (prev > 0 ? prev - 1 : prev));
        } else if (e.key === 'Enter') {
            if (dropdownSelectedIndex >= 0 && dropdownSelectedIndex < lookupFilteredCatalog.length) {
                e.preventDefault();
                handleSelectProduct(lookupFilteredCatalog[dropdownSelectedIndex]);
            }
        } else if (e.key === 'Escape') {
            setCatalogLookup(null);
        }
    };

    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [catalogLookup, lookupFilteredCatalog, dropdownSelectedIndex]);

  const effectiveIssueCount = validationResult ? validationResult.errors.length : validationIssues;
  const sectionNames = useMemo(() => Array.from(new Set(allData.map(d => d.section || 'Unspecified'))).sort(), [allData]);

  const startResize = (col: string, e: React.MouseEvent) => {
      e.preventDefault(); e.stopPropagation();
      resizingRef.current = { col, startX: e.clientX, startWidth: columnWidths[col] || 100 };
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
      if (!resizingRef.current) return;
      const { col, startX, startWidth } = resizingRef.current;
      const diff = e.clientX - startX;
      setColumnWidths(prev => ({ ...prev, [col]: Math.max(20, startWidth + diff) }));
      setHasSavedWidths(true);
  }, []);

  const handleMouseUp = useCallback(() => {
      resizingRef.current = null;
      document.body.style.cursor = '';
      document.body.style.removeProperty('user-select');
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
  }, [handleMouseMove]);

  const handleColumnDragStart = (e: React.DragEvent, colId: string) => { setDraggedColumnId(colId); e.dataTransfer.effectAllowed = 'move'; e.dataTransfer.setData('text/plain', colId); };
  const handleColumnDragOver = (e: React.DragEvent, targetColId: string) => { e.preventDefault(); if (draggedColumnId === targetColId) return; e.dataTransfer.dropEffect = 'move'; };
  const handleColumnDrop = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedColumnId || draggedColumnId === targetColId) { setDraggedColumnId(null); return; }
      setColumnOrder(prev => {
          const newOrder = [...prev];
          const draggedIdx = newOrder.indexOf(draggedColumnId as any);
          const targetIdx = newOrder.indexOf(targetColId as any);
          if (draggedIdx === -1 || targetIdx === -1) return prev;
          newOrder.splice(draggedIdx, 1);
          newOrder.splice(targetIdx, 0, draggedColumnId as any);
          return newOrder;
      });
      setDraggedColumnId(null);
  };

  const groupedData = useMemo(() => {
      if (!isGrouped) return [['All Items', processedData]] as const;
      const groupMap = new Map<string, ParsedLine[]>();
      processedData.forEach(row => {
          const key = row.section || 'Unspecified';
          if (!groupMap.has(key)) groupMap.set(key, []);
          groupMap.get(key)!.push(row);
      });
      return sortConfig ? Array.from(groupMap.entries()).sort((a, b) => a[0].localeCompare(b[0])) : Array.from(groupMap.entries());
  }, [processedData, iGrouped, sortConfig]);

  const handleSelectProduct = (product: CatalogProduct) => {
      if (!catalogLookup) return;
      const targetRowId = catalogLookup.rowId;
      isCommittingRef.current = true;
      setCatalogLookup(null);
      setDropdownSelectedIndex(-1);
      onUpdateRow(targetRowId, 'spruceItemNo', product.itemNo);
      queueMicrotask(() => { isCommittingRef.current = false; });
  };

  const handleOpenLookup = (rowId: string, field: 'spruceItemNo' | 'spruceDescription', ref: React.RefObject<HTMLTableCellElement>, val: string) => {
    setCatalogLookup({ rowId, field, targetRef: ref, searchTerm: val });
    setDropdownSelectedIndex(-1);
  };

  const handleBulkMove = (sectionName: string) => { 
    if (onBulkUpdate) { 
        const targets = moveMenuRowId ? [moveMenuRowId] : Array.from(selectedItems);
        onBulkUpdate(targets, 'section', sectionName); 
        setBulkMenuMode('none'); 
        setMoveMenuRowId(null);
        setSelectedItems(new Set()); 
    } 
  };

  const handleBulkEditApply = () => {
      if (onBulkUpdate && bulkEditField && bulkEditValue) {
          let finalVal: any = bulkEditValue;
          if (bulkEditField === 'qty' || bulkEditField === 'length') finalVal = parseFloat(bulkEditValue);
          onBulkUpdate(Array.from(selectedItems), bulkEditField as keyof ParsedLine, finalVal);
          setBulkMenuMode('none'); setSelectedItems(new Set()); setBulkEditField(''); setBulkEditValue('');
      }
  };

  const handleNavigate = useCallback((e: React.KeyboardEvent, direction: 'up' | 'down' | 'left' | 'right' | 'enter', columnKey: string) => {
    const activeElement = document.activeElement;
    if (!activeElement) return;
    const currentTr = activeElement.closest('tr');
    if (!currentTr) return;
    const table = currentTr.closest('table');
    if (!table) return;
    const inputs = Array.from(table.querySelectorAll('.cell-input')) as (HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement)[];
    const currentIndex = inputs.indexOf(activeElement as any);
    if (currentIndex === -1) return;
    const activateAndFocus = (target: HTMLElement | null) => {
        if (target) {
            e.preventDefault();
            const rowId = target.getAttribute('data-row-id');
            if (rowId) onRowClick(rowId);
            target.focus();
            if ('select' in target) (target as any).select();
        }
    };
    if (direction === 'left') { if (currentIndex > 0) activateAndFocus(inputs[currentIndex - 1]); }
    else if (direction === 'right') { if (currentIndex < inputs.length - 1) activateAndFocus(inputs[currentIndex + 1]); }
    else if (direction === 'up') {
        let prevTr = currentTr.previousElementSibling;
        while (prevTr && prevTr.querySelector('[colspan]')) prevTr = prevTr.previousElementSibling;
        if (prevTr) activateAndFocus(prevTr.querySelector(`[data-col-key="${columnKey}"]`) as HTMLElement);
    } else if (direction === 'down' || direction === 'enter') {
        let nextTr = currentTr.nextElementSibling;
        while (nextTr && nextTr.querySelector('[colspan]')) nextTr = nextTr.nextElementSibling;
        if (nextTr) activateAndFocus(nextTr.querySelector(`[data-col-key="${columnKey}"]`) as HTMLElement);
    }
  }, [onRowClick]);

  const getWastageIconColor = (pct: number) => {
    if (pct < 5) return 'text-green-600';
    if (pct <= 10) return 'text-yellow-500';
    return 'text-red-600';
  };

  const safeWastagePct = Math.max(0, Number(pineWastagePct) || 0);

  const handleSaveWidthsAsDefault = () => {
      if (onSaveColumnWidths) {
          onSaveColumnWidths(columnWidths);
          setHasSavedWidths(true);
          setShowColumnMenu(false);
          alert("Default column widths saved for your profile.");
      }
  };

  const handleResetToAutoWidths = () => {
      setHasSavedWidths(false);
      handleAutoFitAll();
      setShowColumnMenu(false);
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-lg shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] border border-slate-200 dark:border-slate-700 overflow-hidden flex flex-col transition-colors relative h-full">
      <div className="p-1.5 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex flex-col md:flex-row gap-1.5 justify-between items-center sticky top-0 z-30">
        <div className="flex items-center gap-2 w-full md:w-auto flex-1">
            <div className="relative w-full md:w-64 group">
                <div className="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none"><Search className="h-3.5 w-3.5 text-slate-400 group-focus-within:text-blue-500 transition-colors" /></div>
                <input type="text" placeholder="Filter items..." className="pl-8 pr-6 py-1 w-full bg-white dark:bg-slate-955 border border-slate-200 dark:border-slate-700 rounded-md text-sm text-slate-800 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-400 transition-all placeholder:text-slate-400 dark:placeholder:text-slate-600 shadow-sm" value={filterText} onChange={(e) => setFilterText(e.target.value)} />
                {filterText && <button onClick={() => setFilterText('')} className="absolute inset-y-0 right-0 pr-2 flex items-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"><X className="h-3.5 w-3.5" /></button>}
            </div>

            {uiPreferences?.showCatalogMapping && (
                <button 
                    data-mapping-indicator="true"
                    onClick={() => setShowOnlyUnmapped(!showOnlyUnmapped)}
                    className={`flex items-center gap-1.5 px-2 py-1 rounded-md border transition-all hover:shadow-md active:scale-95 ${
                        showOnlyUnmapped 
                        ? 'bg-blue-600 border-blue-700 text-white shadow-lg ring-2 ring-blue-500/20' 
                        : mappingStats.percent > 90 ? 'bg-emerald-50 border-emerald-200 text-emerald-700 dark:bg-emerald-900/20 dark:border-emerald-800 dark:text-emerald-400 hover:bg-emerald-100' 
                        : mappingStats.percent > 50 ? 'bg-amber-50 border-amber-200 text-amber-700 dark:bg-amber-900/20 dark:border-amber-800 dark:text-amber-400 hover:bg-amber-100' 
                        : 'bg-slate-50 border-slate-200 text-slate-600 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 hover:bg-slate-100'
                    }`} 
                    title={showOnlyUnmapped ? "Showing ONLY unmapped items. Click to show all." : `Click to filter: Showing ${mappingStats.count} of ${allData.length} items mapped to ERP catalog`}
                >
                    <ShieldCheck size={12} className={showOnlyUnmapped ? 'text-blue-100' : mappingStats.percent > 70 ? 'text-emerald-500' : 'text-slate-400'} />
                    <span className="text-[10px] font-bold whitespace-nowrap">
                        {showOnlyUnmapped ? 'Unmapped' : `ERP: ${mappingStats.percent}%`}
                    </span>
                </button>
            )}

            <button 
                data-wastage-anchor="true"
                onClick={() => setshowPineWastage(true)} 
                className="flex items-center gap-1.5 px-2 py-1 rounded-md border border-emerald-200 bg-emerald-50 text-emerald-600 hover:bg-emerald-100 hover:shadow-md transition-all active:scale-95" 
                title={`Pine Wastage: ${safeWastagePct.toFixed(1)}% (Click for analysis)`}
            >
                <TrendingUp size={12} className={getWastageIconColor(safeWastagePct)} />
                <span className="text-[10px] font-black uppercase tracking-tight">Wastage</span>
            </button>
        </div>
        <div className="flex items-center gap-1.5">
            {onReparse && (
                <button 
                    onClick={onReparse}
                    disabled={isReparsing}
                    className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-[11px] font-bold border transition-all shadow-sm ${
                        isReparsing 
                        ? 'bg-slate-100 border-slate-200 text-slate-400 cursor-not-allowed' 
                        : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200 dark:hover:bg-slate-700'
                    }`}
                    title="Re-run parse pipeline on current document"
                >
                    {isReparsing ? (
                        <Loader2 size={12} className="animate-spin text-blue-500" />
                    ) : (
                        <RotateCcw size={12} className="text-blue-600 dark:text-blue-400" />
                    )}
                    <span>Reparse</span>
                </button>
            )}
            {uiPreferences?.showGroupControl && (
                <button onClick={() => setIsGrouped(!isGrouped)} className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[11px] font-medium border transition-all ${isGrouped ? 'bg-blue-50 border-blue-200 text-blue-600 dark:bg-blue-900/30 dark:border-blue-800 dark:text-blue-400' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300 dark:hover:bg-slate-700'}`}><Layers size={12} /><span className="hidden sm:inline">Group</span></button>
            )}
            {uiPreferences?.showColumnsControl && (
                <div className="relative">
                    <button onClick={() => setShowColumnMenu(!showColumnMenu)} className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[11px] font-medium border transition-all ${showColumnMenu ? 'bg-blue-50 border-blue-200 text-blue-600 dark:bg-blue-900/30 dark:border-blue-800 dark:text-blue-400' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300 dark:hover:bg-slate-700'}`}><Columns size={12} /><span className="hidden sm:inline">Columns</span></button>
                    {showColumnMenu && (
                        <>
                            <div className="fixed inset-0 z-30" onClick={() => setShowColumnMenu(false)}></div>
                            <div className="absolute right-0 top-full mt-2 w-64 bg-white dark:bg-slate-800 rounded-lg shadow-xl border border-slate-200 dark:border-slate-700 z-40 overflow-hidden p-2 animate-in fade-in zoom-in-95 origin-top-right">
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider px-2 py-1 mb-1 text-left">Visibility & Sizing</div>
                                <div className="px-2 mb-2">
                                    <button 
                                        onClick={handleAutoFitAll}
                                        className="w-full text-left px-3 py-2 rounded-lg text-xs font-bold flex items-center gap-2 text-emerald-600 hover:bg-emerald-50 dark:text-emerald-400 dark:hover:bg-emerald-900/30 transition-all border border-emerald-100 dark:border-emerald-800/50 mb-1"
                                    >
                                        <Maximize2 size={14} /> Auto Fit All Columns
                                    </button>
                                </div>
                                <div className="max-h-[60vh] overflow-y-auto">
                                    {columnOrder.map(col => {
                                        if (col === 'status') return null; 
                                        const isVisible = !hiddenColumns.has(col);
                                        return (<button key={col} onClick={() => { 
                                            const next = new Set(hiddenColumns); 
                                            isVisible ? next.add(col) : next.delete(col); 
                                            setHiddenColumns(next); 
                                            if (col === 'section') setUserTouchedGroupVisibility(true); // Track manual override
                                        }} className="w-full text-left px-3 py-2 rounded-lg text-sm flex items-center justify-between hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"><span className={`font-medium ${isVisible ? 'text-slate-800 dark:text-slate-200' : 'text-slate-400'}`}>{COLUMN_LABELS[col as string]}</span>{isVisible ? <Check size={14} className="text-blue-500" /> : <EyeOff size={14} className="text-slate-400" />}</button>);
                                    })}
                                </div>
                                <div className="border-t border-slate-100 dark:border-slate-700 mt-2 pt-2 flex flex-col gap-1">
                                    <button 
                                        onClick={handleSaveWidthsAsDefault}
                                        className="w-full text-left px-3 py-2 rounded-lg text-xs font-bold flex items-center gap-2 text-blue-600 hover:bg-blue-50 dark:text-blue-400 dark:hover:bg-blue-900/30 transition-all"
                                    >
                                        <Save size={14} /> Save current layout as default
                                    </button>
                                    {hasSavedWidths && (
                                        <button 
                                            onClick={handleResetToAutoWidths}
                                            className="w-full text-left px-3 py-2 rounded-lg text-xs font-bold flex items-center gap-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 transition-all"
                                        >
                                            <RotateCcw size={14} /> Reset to auto-widths
                                        </button>
                                    )}
                                </div>
                            </div>
                        </>
                    )}
                </div>
            )}
            {onExport && uiPreferences?.showExportControl && <button onClick={onExport} className="flex items-center gap-1.5 px-2 py-1 rounded-md text-[11px] font-bold bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all"><FileDown size={12} className="text-blue-600 dark:text-blue-400" /><span>Export</span></button>}
            {onAddRow && uiPreferences?.showAddControl && <button onClick={() => onAddRow()} className="flex items-center gap-1.5 px-2 py-1 rounded-md text-[11px] font-bold bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all"><Plus size={12} className="text-green-600 dark:text-green-400" /><span>Add</span></button>}
        </div>
      </div>

      <div className="flex-1 flex flex-col min-w-0 bg-white dark:bg-slate-900 overflow-hidden relative">
        <div className="overflow-x-auto overflow-y-auto flex-1 scroll-smooth">
            <table className="min-w-full text-[13px] text-left border-separate border-spacing-0 table-auto">
            <thead className="sticky top-0 z-20 shadow-sm">
                <tr>
                <th className="w-6 px-1 py-1 border-y border-l border-r border-slate-200 dark:border-slate-800 bg-slate-50/95 dark:bg-slate-900/95 backdrop-blur-md">
                    <button onClick={() => { selectedItems.size === processedData.length && processedData.length > 0 ? setSelectedItems(new Set()) : setSelectedItems(new Set(processedData.map(d => d.id))); }} className="text-slate-400 hover:text-slate-600 dark:text-slate-500 dark:hover:text-slate-300 flex items-center justify-center w-full transition-colors active:scale-95">{processedData.length > 0 && selectedItems.size === processedData.length ? <CheckSquare size={14} /> : <Square size={14} />}</button>
                </th>
                {visibleColumns.map(colId => (
                    <th key={colId} data-col-id={colId} style={{ minWidth: `${columnWidths[colId as string]}px` }} draggable={colId !== 'status'} onDragStart={(e) => handleColumnDragStart(e, colId)} onDragOver={(e) => handleColumnDragOver(e, colId)} onDrop={(e) => handleColumnDrop(e, colId)} className={`px-1 py-1 border-y border-r border-slate-200 dark:border-slate-800 bg-slate-50/95 dark:bg-slate-900/95 backdrop-blur-md text-slate-500 dark:text-slate-300 font-semibold uppercase text-[9px] tracking-wide select-none group transition-all relative text-left ${colId !== 'status' ? 'cursor-grab active:cursor-grabbing hover:bg-slate-100 dark:hover:bg-slate-800/80' : ''} ${draggedColumnId === colId ? 'opacity-40' : ''}`}>
                        <div className="flex items-center gap-1 justify-start h-full">
                            <div className={`flex items-center gap-1 flex-1 overflow-hidden justify-start`} onClick={() => { let direction: SortDirection = 'asc'; if (sortConfig && sortConfig.key === colId && sortConfig.direction === 'asc') direction = 'desc'; setSortConfig({ key: colId as any, direction }); }}>
                                {colId !== 'status' && <GripHorizontal size={8} className="text-slate-300 group-hover:text-slate-400 shrink-0" />}
                                <span className="whitespace-normal break-words">{colId === 'status' ? <Activity size={12} className="text-slate-400" /> : COLUMN_LABELS[colId as string]}</span>
                                {sortConfig?.key === colId && (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-blue-600 ml-0.5" /> : <ArrowDown size={12} className="text-blue-600 ml-0.5" />)}
                            </div>
                            {colId !== 'status' && (
                                <button 
                                    onClick={(e) => { e.stopPropagation(); handleAutoFitColumn(colId as string); }}
                                    className="opacity-0 group-hover:opacity-100 p-0.5 text-slate-300 hover:text-blue-500 transition-all"
                                    title="Auto fit width"
                                >
                                    <Maximize2 size={10} />
                                </button>
                            )}
                        </div>
                        <div className="absolute right-0 top-0 bottom-0 w-0.5 cursor-col-resize hover:bg-blue-400 z-10 group-hover:bg-slate-300 dark:group-hover:bg-slate-700/50 transition-colors" onMouseDown={(e) => startResize(colId as string, e)} />
                    </th>
                ))}
                <th className="px-1 py-1 w-12 border-y border-r border-slate-200 dark:border-slate-800 bg-slate-50/95 dark:bg-slate-900/95 backdrop-blur-md"></th>
                </tr>
            </thead>
            <tbody>
                {groupedData.map(([groupName, groupRows]) => {
                    let calcLM = 0, calcPrice = 0, calcM2 = 0;
                    const isCollapsed = collapsedGroups.has(groupName);
                    groupRows.forEach(r => { if (!isSummaryRow(r)) { if (r.unit === 'L/M') calcLM += r.total; else if (r.unit === 'm2') calcM2 += r.total; calcPrice += (r.totalPrice || 0); } });
                    return (
                        // Added comment to address lint error: Explicitly using React.Fragment to ensure it refers to the imported React module.
                        <React.Fragment key={groupName}>
                            {isGrouped && (
                                <tr className="bg-slate-100 dark:bg-slate-800/80 transition-colors">
                                    <td colSpan={visibleColumns.length + 2} className="px-2 py-1 border-y border-slate-200 dark:border-slate-700 text-[10px] uppercase text-slate-600 dark:text-slate-200 tracking-wider text-left">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-2">
                                                <button onClick={(e) => { e.stopPropagation(); const next = new Set(collapsedGroups); isCollapsed ? next.delete(groupName) : next.add(groupName); setCollapsedGroups(next); }} className="p-0.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded text-slate-400 hover:text-blue-500" title={isCollapsed ? "Expand section" : "Collapse section"}>{isCollapsed ? <ChevronRight size={14} /> : <ChevronDown size={14} />}</button>
                                                <div className="flex items-center gap-1 font-bold whitespace-normal break-words text-left"><Layers size={12} className="text-slate-400 shrink-0" />{groupName}</div>
                                                <span className="bg-slate-200 dark:bg-slate-700 text-slate-500 dark:text-slate-400 px-1 rounded font-bold whitespace-nowrap">{groupRows.length} Items</span>
                                            </div>
                                            <div className="flex items-center gap-3 font-medium text-slate-500 dark:text-slate-400 text-left">
                                                {calcLM > 0 && <span className="whitespace-nowrap">LM: <strong className="text-slate-800 dark:text-slate-100">{calcLM.toFixed(1)}m</strong></span>}
                                                {calcPrice > 0 && <span className="whitespace-nowrap">Price: <strong className="text-emerald-700 dark:text-emerald-400">${calcPrice.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong></span>}
                                            </div>
                                        </div>
                                    </td>
                                </tr>
                            )}
                            {!isCollapsed && groupRows.map((row) => (
                                <TableRow 
                                    key={row.id} 
                                    row={row} 
                                    onUpdateRow={onUpdateRow} 
                                    visibleColumns={visibleColumns as any} 
                                    isActive={activeRowId === row.id} 
                                    onClick={() => onRowClick(row.id)} 
                                    onDelete={onDeleteRow && !row.locked ? () => setDeleteCandidateId(row.id) : undefined} 
                                    isSelected={selectedItems.has(row.id)} 
                                    onToggleSelect={(id) => { const next = new Set(selectedItems); next.has(id) ? next.delete(id) : next.add(id); setSelectedItems(next); }} 
                                    hasMultipleSources={false} 
                                    onTeach={onTeach} 
                                    onInspect={onInspect} 
                                    isSummary={isSummaryRow(row)} 
                                    onOpenMoveMenu={() => { onRowClick(row.id); setMoveMenuRowId(row.id); setBulkMenuMode('move'); }} 
                                    onOpenCatalogLookup={handleOpenLookup} 
                                    onNavigate={handleNavigate} 
                                    catalog={catalog} 
                                    uiPreferences={uiPreferences} 
                                    isCommittingRef={isCommittingRef}
                                    isLookupOpen={!!catalogLookup && catalogLookup.rowId === row.id}
                                />
                            ))}
                        {/* Added comment to address lint error: Explicitly using React.Fragment to ensure it refers to the imported React module. */}
                        </React.Fragment>
                    );
                })}
            </tbody>
            </table>
        </div>
      </div>
      {catalogLookup && (
        <CatalogDropdown 
            catalog={catalog} 
            targetRef={catalogLookup.targetRef} 
            searchTerm={catalogLookup.searchTerm} 
            onSelect={handleSelectProduct} 
            onClose={() => setCatalogLookup(null)} 
            selectedIndex={dropdownSelectedIndex}
        />
      )}
      <PineWastagePanel 
          isOpen={showPineWastage} 
          onClose={() => setshowPineWastage(false)} 
          lines={allData} 
          catalog={catalog} 
          onSelectSourceLine={(id) => {
              onRowClick(id);
          }}
      />
      {bulkMenuMode !== 'none' && (
          <>
            <div className="fixed inset-0 z-50" onClick={() => { setBulkMenuMode('none'); setMoveMenuRowId(null); }}></div>
            <div className="fixed bottom-20 left-1/2 -translate-x-1/2 z-[60] bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 w-80 animate-in slide-in-from-bottom-2 duration-200 overflow-hidden">
                <div className="p-3 bg-slate-50 dark:bg-slate-900 border-b border-slate-100 dark:border-slate-700 flex items-center justify-between"><span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">{bulkMenuMode === 'move' ? <Move size={14} /> : <Edit2 size={14} />} {bulkMenuMode === 'move' ? (moveMenuRowId ? 'Move Item' : 'Bulk Move Items') : 'Bulk Edit Field'}</span><button onClick={() => { setBulkMenuMode('none'); setMoveMenuRowId(null); }}><X size={16} className="text-slate-400" /></button></div>
                <div className="p-4">
                    {bulkMenuMode === 'move' ? (
                        <div className="space-y-1 max-h-[300px] overflow-y-auto pr-1">
                            {sectionNames.map(name => ( <button key={name} onClick={() => handleBulkMove(name)} className="w-full text-left px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-lg transition-colors flex items-center justify-between"><span className="whitespace-normal break-words">{name}</span><ChevronRight size={14} className="text-slate-300 shrink-0" /></button> ))}
                            <button onClick={() => { const name = prompt("Enter new group name:"); if (name) handleBulkMove(name); }} className="w-full text-left px-3 py-2 text-sm text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-lg transition-colors border border-dashed border-blue-200 dark:border-blue-800 mt-2 flex items-center gap-2"><Plus size={14} /> New Group...</button>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Select Field</label><select value={bulkEditField} onChange={(e) => setBulkEditField(e.target.value as any)} className="w-full p-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm dark:text-slate-200"><option value="">Choose column...</option><option value="item">Item Name</option><option value="dimensions">Dimensions</option><option value="grade">Grade</option><option value="unit">Unit</option><option value="qty">Quantity</option><option value="length">Length</option></select></div>
                            <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">New Value</label>
                                {bulkEditField === 'unit' ? ( <select value={bulkEditValue} onChange={(e) => setBulkEditValue(e.target.value)} className="w-full p-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm dark:text-slate-200"><option value="">Choose unit...</option><option value="L/M">L/M</option><option value="EA">EA</option><option value="m2">m2</option></select>
                                ) : ( <input type={bulkEditField === 'qty' || bulkEditField === 'length' ? 'number' : 'text'} value={bulkEditValue} onChange={(e) => setBulkEditValue(e.target.value)} className="w-full p-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm dark:text-slate-200" placeholder="Enter value..." /> )}
                            </div>
                            <button onClick={handleBulkEditApply} disabled={!bulkEditField || !bulkEditValue} className="w-full py-2.5 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-blue-500/20 transition-all"><Check size={16} /> Apply to {selectedItems.size} items</button>
                        </div>
                    )}
                </div>
            </div>
          </>
      )}
      {selectedItems.size > 0 && !moveMenuRowId && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[60] bg-slate-900/95 dark:bg-slate-800/95 text-white rounded-2xl shadow-2xl border border-white/10 p-2 pl-4 flex items-center gap-4 animate-in slide-in-from-bottom-8 duration-300 backdrop-blur-xl ring-1 ring-black/40">
                <div className="flex flex-col"><div className="font-bold text-xs whitespace-nowrap text-white">{selectedItems.size} Items Selected</div><button onClick={() => setSelectedItems(new Set())} className="text-[10px] text-blue-400 hover:text-blue-300 text-left font-medium">Deselect all</button></div>
                <div className="h-8 w-px bg-slate-700 mx-1"></div>
                <div className="flex items-center gap-1">
                    <button type="button" onClick={() => setBulkMenuMode('move')} className={`px-3 py-1.5 hover:bg-white/10 text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-colors whitespace-nowrap ${bulkMenuMode === 'move' ? 'bg-white/20' : ''}`}><ArrowRightLeft size={14} className="text-blue-400" /> Move</button>
                    <button type="button" onClick={() => setBulkMenuMode('edit')} className={`px-3 py-1.5 hover:bg-white/10 text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-colors whitespace-nowrap ${bulkMenuMode === 'edit' ? 'bg-white/20' : ''}`}><Edit2 size={14} className="text-amber-400" /> Edit</button>
                    <button type="button" onClick={() => setshowBulkDeleteConfirm(true)} className="px-3 py-1.5 hover:bg-red-500/20 text-red-400 hover:text-red-300 rounded-xl text-xs font-bold flex items-center gap-2 transition-colors whitespace-nowrap"><Trash2 size={14} /> Delete</button>
                </div>
                <button type="button" onClick={() => setSelectedItems(new Set())} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors"><X size={18} /></button>
            </div>
        )}
      <ConfirmDialog isOpen={!!deleteCandidateId} title="Delete Item" message="Are you sure you want to delete this item?" confirmLabel="Delete" isDestructive={true} onConfirm={() => { if (deleteCandidateId && onDeleteRow) onDeleteRow(deleteCandidateId); setDeleteCandidateId(null); }} onCancel={() => setDeleteCandidateId(null)} />
      <ConfirmDialog isOpen={showBulkDeleteConfirm} title="Delete Multiple Items" message={`Are you sure you want to delete ${selectedItems.size} selected items?`} confirmLabel={`Delete ${selectedItems.size} Items`} isDestructive={true} onConfirm={() => { if (onBulkDelete) onBulkDelete(Array.from(selectedItems)); setSelectedItems(new Set()); setshowBulkDeleteConfirm(false); }} onCancel={() => setshowBulkDeleteConfirm(false)} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ExportTemplate, ExportColumn, ParsedLine, ExportValidation } from '../types';
import { templateService } from '../services/excelService';
import { Plus, Trash2, Save, MoveUp, MoveDown, ArrowLeft, LayoutTemplate, Columns, Edit2, ShieldAlert, ChevronDown, ChevronUp, Star } from 'lucide-react';

interface TemplateManagerProps {
  onClose: () => void;
}

const FIELD_OPTIONS: { label: string; value: ExportColumn['field'] }[] = [
    { label: 'Section', value: 'section' },
    { label: 'Sub Section', value: 'subSection' },
    { label: 'Item Description', value: 'item' },
    { label: 'Dimensions', value: 'dimensions' },
    { label: 'Grade', value: 'grade' },
    { label: 'Quantity', value: 'qty' },
    { label: 'Length', value: 'length' },
    { label: 'Unit (L/M, EA)', value: 'unit' },
    { label: 'Total', value: 'total' },
    { label: 'Price / Unit', value: 'price' },
    { label: 'Total Price ($)', value: 'totalPrice' },
    { label: 'Job Notes', value: 'parsingNotes' }, 
    { label: 'Original Line', value: 'originalLine' },
    { label: '--- Job Metadata ---', value: 'empty' },
    { label: 'Builder Name', value: 'meta_builder' },
    { label: 'Site Address', value: 'meta_site' },
    { label: 'Job Number', value: 'meta_job' },
    { label: 'Takeoff Date', value: 'meta_date' },
    { label: '-------------------', value: 'empty' },
    { label: 'Custom Text (Fixed)', value: 'custom_text' },
    { label: 'Empty Column', value: 'empty' },
];

const TRANSFORM_OPTIONS = [
    { label: 'None', value: 'none' },
    { label: 'Uppercase', value: 'uppercase' },
    { label: 'Lowercase', value: 'lowercase' },
    { label: 'Number (0 decimals)', value: 'number_0' },
    { label: 'Number (2 decimals)', value: 'number_2' },
    { label: 'Trim Whitespace', value: 'trim' },
];

export const TemplateManager: React.FC<TemplateManagerProps> = ({ onClose }) => {
  const [templates, setTemplates] = useState<ExportTemplate[]>([]);
  const [activeTemplate, setActiveTemplate] = useState<ExportTemplate | null>(null);
  const [isDirty, setIsDirty] = useState(false);
  const [expandedColId, setExpandedColId] = useState<string | null>(null);

  useEffect(() => {
    setTemplates(templateService.getTemplates());
  }, []);

  const handleSelectTemplate = (t: ExportTemplate) => {
      // Deep copy to avoid mutating state directly
      setActiveTemplate(JSON.parse(JSON.stringify(t)));
      setIsDirty(false);
      setExpandedColId(null);
  };

  const handleCreateNew = () => {
      const newTemplate: ExportTemplate = {
          id: crypto.randomUUID(),
          name: 'New Custom Template',
          isDefault: false,
          columns: [
              { id: crypto.randomUUID(), header: 'Description', field: 'item', transform: 'none' },
              { id: crypto.randomUUID(), header: 'Qty', field: 'qty', transform: 'number_0' },
          ]
      };
      setActiveTemplate(newTemplate);
      setIsDirty(true);
      setExpandedColId(null);
  };

  const handleDelete = (id: string) => {
      if (confirm('Delete this template?')) {
          templateService.deleteTemplate(id);
          setTemplates(templateService.getTemplates());
          if (activeTemplate?.id === id) setActiveTemplate(null);
      }
  };

  const handleSave = () => {
      if (activeTemplate) {
          templateService.saveTemplate(activeTemplate);
          setTemplates(templateService.getTemplates());
          setIsDirty(false);
      }
  };

  const toggleDefault = () => {
      if (!activeTemplate) return;
      setActiveTemplate({ ...activeTemplate, isDefault: !activeTemplate.isDefault });
      setIsDirty(true);
  };

  const updateColumn = (colId: string, field: keyof ExportColumn, value: any) => {
      if (!activeTemplate) return;
      const updatedCols = activeTemplate.columns.map(c => 
          c.id === colId ? { ...c, [field]: value } : c
      );
      setActiveTemplate({ ...activeTemplate, columns: updatedCols });
      setIsDirty(true);
  };

  const toggleValidation = (colId: string, type: ExportValidation['type'], enabled: boolean) => {
      if (!activeTemplate) return;

      const col = activeTemplate.columns.find(c => c.id === colId);
      if (!col) return;

      let currentValidations = col.validations || [];

      if (enabled) {
          if (!currentValidations.find(v => v.type === type)) {
              currentValidations = [...currentValidations, { type }];
          }
      } else {
          currentValidations = currentValidations.filter(v => v.type !== type);
      }

      updateColumn(colId, 'validations', currentValidations);
  };

  const updateValidationValue = (colId: string, type: ExportValidation['type'], value: number) => {
      if (!activeTemplate) return;
      const col = activeTemplate.columns.find(c => c.id === colId);
      if (!col) return;

      const currentValidations = (col.validations || []).map(v => 
          v.type === type ? { ...v, value } : v
      );
      updateColumn(colId, 'validations', currentValidations);
  };

  const addColumn = () => {
      if (!activeTemplate) return;
      const newCol: ExportColumn = {
          id: crypto.randomUUID(),
          header: 'New Column',
          field: 'empty',
          transform: 'none'
      };
      setActiveTemplate({ ...activeTemplate, columns: [...activeTemplate.columns, newCol] });
      setIsDirty(true);
  };

  const removeColumn = (colId: string) => {
      if (!activeTemplate) return;
      setActiveTemplate({ 
          ...activeTemplate, 
          columns: activeTemplate.columns.filter(c => c.id !== colId) 
      });
      setIsDirty(true);
  };

  const moveColumn = (index: number, direction: -1 | 1) => {
      if (!activeTemplate) return;
      const newCols = [...activeTemplate.columns];
      const targetIndex = index + direction;
      if (targetIndex < 0 || targetIndex >= newCols.length) return;

      const temp = newCols[index];
      newCols[index] = newCols[targetIndex];
      newCols[targetIndex] = temp;

      setActiveTemplate({ ...activeTemplate, columns: newCols });
      setIsDirty(true);
  };

  return (
    <div className="flex h-full bg-white dark:bg-slate-900 overflow-hidden animate-fade-in">
        {/* Sidebar List */}
        <div className="w-64 border-r border-slate-200 dark:border-slate-700 flex flex-col bg-slate-50 dark:bg-slate-800/50">
            <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex items-center justify-between">
                <h3 className="font-bold text-slate-700 dark:text-slate-200 flex items-center gap-2">
                    <LayoutTemplate size={18} /> Templates
                </h3>
                <button onClick={handleCreateNew} className="p-1.5 bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400 rounded-lg hover:bg-blue-200">
                    <Plus size={16} />
                </button>
            </div>
            <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {templates.map(t => (
                    <button
                        key={t.id}
                        onClick={() => handleSelectTemplate(t)}
                        className={`w-full text-left px-3 py-2 rounded-lg text-sm flex items-center justify-between group ${
                            activeTemplate?.id === t.id 
                            ? 'bg-blue-600 text-white shadow-md' 
                            : 'hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300'
                        }`}
                    >
                        <div className="flex items-center gap-2 min-w-0">
                            {t.isDefault && <Star size={12} className="text-amber-400 fill-amber-400 shrink-0" />}
                            <span className="truncate font-medium">{t.name}</span>
                        </div>
                        <div className="opacity-0 group-hover:opacity-100 flex gap-1" onClick={e => e.stopPropagation()}>
                            <Trash2 
                                size={14} 
                                className="hover:text-red-300 cursor-pointer" 
                                onClick={() => handleDelete(t.id)}
                            />
                        </div>
                    </button>
                ))}
            </div>
            <div className="p-4 border-t border-slate-200 dark:border-slate-700">
                <button onClick={onClose} className="w-full py-2 flex items-center justify-center gap-2 text-slate-600 dark:text-slate-400 hover:text-slate-900 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors">
                    <ArrowLeft size={16} /> Back
                </button>
            </div>
        </div>

        {/* Editor Area */}
        <div className="flex-1 flex flex-col min-w-0">
            {activeTemplate ? (
                <>
                    {/* Toolbar */}
                    <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 flex justify-between items-center">
                        <div className="flex items-center gap-4 flex-1 min-w-0">
                             <input 
                                type="text" 
                                value={activeTemplate.name}
                                onChange={(e) => {
                                    setActiveTemplate({ ...activeTemplate, name: e.target.value });
                                    setIsDirty(true);
                                }}
                                className="text-lg font-bold text-slate-800 dark:text-white bg-transparent border-b border-transparent hover:border-slate-300 focus:border-blue-500 focus:outline-none flex-1"
                             />
                             <button 
                                onClick={toggleDefault}
                                className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${
                                    activeTemplate.isDefault 
                                    ? 'bg-amber-100 text-amber-700 border border-amber-200' 
                                    : 'bg-slate-100 text-slate-500 hover:bg-amber-50 hover:text-amber-600 border border-transparent'
                                }`}
                             >
                                <Star size={14} className={activeTemplate.isDefault ? 'fill-amber-500' : ''} />
                                {activeTemplate.isDefault ? 'Default Template' : 'Set as Default'}
                             </button>
                        </div>

                        <button 
                            onClick={handleSave}
                            disabled={!isDirty}
                            className="px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-bold flex items-center gap-2 ml-4"
                        >
                            <Save size={16} /> Save Changes
                        </button>
                    </div>

                    {/* Columns Editor */}
                    <div className="flex-1 overflow-y-auto p-6 bg-slate-50 dark:bg-slate-900">
                        <div className="max-w-4xl mx-auto">
                            <div className="flex items-center justify-between mb-4">
                                <h4 className="text-sm font-bold text-slate-500 uppercase flex items-center gap-2">
                                    <Columns size={16} /> Export Columns ({activeTemplate.columns.length})
                                </h4>
                                <button onClick={addColumn} className="text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center gap-1 bg-blue-50 px-3 py-1.5 rounded-lg border border-blue-200">
                                    <Plus size={14} /> Add Column
                                </button>
                            </div>

                            <div className="space-y-3">
                                {activeTemplate.columns.map((col, index) => {
                                    const isExpanded = expandedColId === col.id;
                                    const required = col.validations?.some(v => v.type === 'required');
                                    const maxLength = col.validations?.find(v => v.type === 'max_length')?.value;
                                    const numericOnly = col.validations?.some(v => v.type === 'numeric_only');
                                    const noSpaces = col.validations?.some(v => v.type === 'no_spaces');

                                    return (
                                        <div key={col.id} className="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm group overflow-hidden">
                                            {/* Header Row */}
                                            <div className="p-3 flex flex-col md:flex-row items-start md:items-center gap-4">
                                                {/* Drag/Order Handles */}
                                                <div className="flex flex-col gap-1 items-center justify-center text-slate-400 pt-2 md:pt-0">
                                                    <button 
                                                        disabled={index === 0} 
                                                        onClick={() => moveColumn(index, -1)}
                                                        className="hover:text-blue-500 disabled:opacity-20"
                                                    >
                                                        <MoveUp size={14} />
                                                    </button>
                                                    <button 
                                                        disabled={index === activeTemplate.columns.length - 1} 
                                                        onClick={() => moveColumn(index, 1)}
                                                        className="hover:text-blue-500 disabled:opacity-20"
                                                    >
                                                        <MoveDown size={14} />
                                                    </button>
                                                </div>

                                                {/* Configuration */}
                                                <div className="flex-1 grid grid-cols-1 md:grid-cols-4 gap-4 w-full">
                                                    <div>
                                                        <label className="text-[10px] uppercase font-bold text-slate-400">CSV Header</label>
                                                        <input 
                                                            type="text" 
                                                            value={col.header}
                                                            onChange={(e) => updateColumn(col.id, 'header', e.target.value)}
                                                            className="w-full text-sm font-medium border-b border-slate-200 dark:border-slate-700 bg-transparent focus:border-blue-500 outline-none pb-1 dark:text-slate-200"
                                                            placeholder="Header Name"
                                                        />
                                                    </div>

                                                    <div>
                                                        <label className="text-[10px] uppercase font-bold text-slate-400">Map to Field</label>
                                                        <select 
                                                            value={col.field}
                                                            onChange={(e) => updateColumn(col.id, 'field', e.target.value)}
                                                            className="w-full text-sm bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 dark:text-slate-200 shadow-sm"
                                                        >
                                                            {FIELD_OPTIONS.map(opt => (
                                                                <option key={opt.value} value={opt.value}>{opt.label}</option>
                                                            ))}
                                                        </select>
                                                    </div>

