const COLUMN_LABELS: Record<string, string> = {
  status: '', 
  section: 'Group',
  subSection: 'Section',
  spruceItemNo: 'SPRUCE Item No.',
  spruceDescription: 'SPRUCE Description',
  spruceGroup: 'Catalog Group',
