};

const DEFAULT_ORDER: (keyof ParsedLine | 'status' | 'totalLm')[] = ['status', 'section', 'subSection', 'spruceItemNo', 'spruceDescription', 'spruceGroup', 'spruceSection', 'item', 'description', 'dimensions', 'grade', 'qty', 'length', 'totalLm', 'unit', 'price', 'totalPrice'];

const DEFAULT_WIDTHS: Record<string, number> = {
  status: 50,
  section: 140,
  subSection: 140,
  spruceItemNo: 130,
  spruceDescription: 200,
  spruceGroup: 140,
  spruceSection: 160,
  item: 280,
  description: 250,
  dimensions: 110,
  grade: 90,
  qty: 80,
  length: 90,
  totalLm: 90,
  unit: 80,
