            setSettings(prev => ({
                ...prev,
                companyName: globalBranding.companyName,
                logoUrl: globalBranding.logoUrl
            }));
        }
        const lastUserId = localStorage.getItem('active_user_id');
        if (lastUserId) {
            const users = await storageService.getUsers();
            const found = users.find(u => lastUserId === u.id);
            if (found) {
                setCurrentUser(found);
                const userSetts = await storageService.getUserSettings(found.id);
                if (userSetts) {
                    setSettings({
                        ...DEFAULT_SETTINGS,
                        ...userSetts,
                        uiPreferences: { ...DEFAULT_UI_PREFS, ...(userSetts.uiPreferences || {}) }
                    });
                }
            }
        }
      } catch (e) {
        console.error("App initialization failed", e);
      }
    };
    loadInit();
  }, []);

  useEffect(() => {
    if (currentUser) {
        localStorage.setItem('active_user_id', currentUser.id);
        storageService.getAll(currentUser.id).then(setHistory);
        storageService.getUserSettings(currentUser.id).then(userSetts => {
            if (userSetts) {
                setSettings({
                    ...DEFAULT_SETTINGS,
                    ...userSetts,
                    uiPreferences: { ...DEFAULT_UI_PREFS, ...(userSetts.uiPreferences || {}) }
                });
            } else {
                setSettings(DEFAULT_SETTINGS);
            }
        });
    } else {
        setHistory([]);
        localStorage.removeItem('active_user_id');
    }
  }, [currentUser]);

  useEffect(() => {
    if (settings.darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    document.documentElement.style.fontSize = settings.fontSize || '14px';
    if (currentUser) {
        storageService.saveUserSettings(currentUser.id, settings);
        if (currentUser.role === 'admin') {
            storageService.saveBranding({
                companyName: settings.companyName,
                logoUrl: settings.logoUrl
            });
        }
    }
  }, [settings, currentUser]);

  // AUTO-ADJUST PDF WIDTH EFFECT
  const handleTotalTableWidthReport = useCallback((requiredTablePx: number) => {
      if (currentView !== 'table' || !splitContainerRef.current || !uiPrefs.showPdfPreview || isResizing || userAdjustedWidth) return;

      const totalAvailableWidth = splitContainerRef.current.clientWidth;
      if (totalAvailableWidth <= 0) return;

      const buffer = 48;
      const effectiveTablePx = requiredTablePx + buffer;
      const minTablePct = 30; 

      let tablePct = (effectiveTablePx / totalAvailableWidth) * 100;
      tablePct = Math.max(minTablePct, Math.min(80, tablePct));

      const newLeftPct = 100 - tablePct;

      if (Math.abs(newLeftPct - leftPanelWidth) > 1) {
          setLeftPanelWidth(newLeftPct);
      }
  }, [currentView, leftPanelWidth, uiPrefs.showPdfPreview, isResizing, userAdjustedWidth]);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
        if (isResizing && splitContainerRef.current) {
            const containerRect = splitContainerRef.current.getBoundingClientRect();
            const newWidth = ((e.clientX - containerRect.left) / containerRect.width) * 100;
            setLeftPanelWidth(Math.max(15, Math.min(80, newWidth)));
            setUserAdjustedWidth(true);
        }
    };
    const handleMouseUp = () => { 
        setIsResizing(false); 
        document.body.style.cursor = 'default'; 
    };
    if (isResizing) {
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = 'col-resize';
    }
    return () => { window.removeEventListener('mousemove', handleMouseMove); window.removeEventListener('mouseup', handleMouseUp); };
  }, [isResizing]);

  const stats: KPIStats = useMemo(() => {
      const totalLm = data.reduce((acc, curr) => {
          if (curr.unit === 'L/M') return acc + curr.total;
          if (curr.isDerived && curr.length) return acc + (curr.total * curr.length);
          return acc;
      }, 0);
      const totalPrice = data.reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);
      return { totalItems: data.length, totalLinearMetres: totalLm, totalPrice: totalPrice };
  }, [data]);

  const pineWastageSummary = useMemo(() => {
      if (data.length === 0) return undefined;
      return computePineWastage(data, catalog).summary;
  }, [data, catalog]);

  const activeDocContext = useMemo(() => {
      if (!activeDocId || documents.length === 0) return null;
      let targetDoc = documents.find(p => p.id === activeDocId) || documents[0];
      let highlightPage: number | undefined = undefined;
      let highlightRect: number[] | undefined = undefined;
      if (activeRowId) {
          const row = data.find(r => r.id === activeRowId);
          if (row && row.page) {
              const owningDoc = documents.find(doc => row.page! > doc.pageOffset && row.page! <= (doc.pageOffset + doc.pageCount));
              if (owningDoc) {
                  highlightPage = row.page! - owningDoc.pageOffset;
                  highlightRect = row.rect;
              }
          }
      }
      return { doc: targetDoc, highlightPage, highlightRect };
  }, [activeDocId, documents, activeRowId, data]);

  const processText = useCallback(async (lines: TextLine[], fileName: string, totalSize: number, profileOverride?: ParseProfile) => {
      if (!currentUser) return;
      setStatus('parsing');
      await new Promise(r => setTimeout(r, 50));
      const profile = profileOverride || detectProfile(lines);
      setActiveProfile(profile);
      setProfileConfidence(profile.detect(lines));
      const rules = learningService.getRules();
      const { items, notes } = parseTakeoff(lines, profile, rules, catalog, learnedMappings);
      const finalItems = items.map(item => {
          if (item.spruceMapped && item.mappingSource === 'MEMORY') return item;
          const exactKey = buildLookupKey(item.item, item.dimensions);
          const noDimsKey = buildLookupKey(item.item, "");
          const match = learnedMappings.get(exactKey) || learnedMappings.get(noDimsKey);
          if (match) {
              const product = catalog.find(p => p.itemNo === match.itemNo);
              if (product) {
                  return { ...item, ...applyMappingToRow(item, { ...product, source: 'MEMORY', matchedFromMemory: true }) };
              }
          }
          return item;
      }).map(item => ({ ...item, totalPrice: (item.price || 0) * item.total }));
      const notesStr = notes.join('\n');
      const meta = extractContactDetails(lines);
      const fullMetadata: FileMetadata = {
          name: fileName, size: totalSize, type: 'application/pdf', ...meta,
          builder: meta.builder || 'Unknown Client',
          pageCount: lines.length > 0 ? Math.max(...lines.map(l => l.page)) : 0
      };
      setData(finalItems);
      setMetadata(fullMetadata);
      setJobNotes(notesStr);
      setRawTextLines(lines);
      if (finalItems.length === 0) setStatus('no_data');
      else {
          setStatus('ready');
          setCurrentView('table');
          storageService.add({
              id: crypto.randomUUID(), userId: currentUser.id, timestamp: Date.now(), fileName: fileName, itemCount: finalItems.length, data: finalItems, metadata: fullMetadata, jobNotes: notesStr
          }).then(() => storageService.getAll(currentUser.id).then(setHistory));
      }
  }, [catalog, learnedMappings, currentUser]);

  const handleReparse = useCallback(async () => {
    if (rawTextLines.length === 0 || !metadata) return;
    await processText(rawTextLines, metadata.name, metadata.size, activeProfile);
  }, [rawTextLines, metadata, activeProfile, processText]);

  const handleFileUpload = async (files: File[]) => {
    if (files.length === 0) return;
    setStatus('extracting');
    setLoadingProgress(5);
    setLoadingMessage(TIMBER_PUNS[0]);
    documents.forEach(d => URL.revokeObjectURL(d.url));
    setDocuments([]);
    await new Promise(r => setTimeout(r, 100));
    let punIndex = 0;
    const punInterval = setInterval(() => { punIndex = (punIndex + 1) % TIMBER_PUNS.length; setLoadingMessage(TIMBER_PUNS[punIndex]); }, 2500);
    const progressInterval = setInterval(() => { setLoadingProgress(prev => { if (prev >= 98) return prev; const step = prev < 85 ? 0.4 : 0.05; return prev + step; }); }, 150);
    try {
        const newDocuments: SourceDocument[] = [];
        let allTextLines: TextLine[] = [];
        let cumulativePageOffset = 0;
        let totalSize = 0;
        for (let i = 0; i < files.length; i++) {
             const file = files[i];
             totalSize += file.size;
             let textLines: TextLine[] = [];
             let pageCount = 0;
             let isExcel = file.name.endsWith('.xlsx') || file.name.endsWith('.xls') || file.name.endsWith('.csv');
             const startFileProgress = 10 + (i / files.length) * 60;
             setLoadingProgress(Math.max(loadingProgress, startFileProgress));
             await new Promise(r => setTimeout(r, 0));
             if (isExcel) { const result = await extractTextFromExcel(file); textLines = result.textLines; pageCount = result.pageCount; }
             else { const result = await extractTextFromPdf(file); textLines = result.textLines; pageCount = result.pageCount; }
             const shiftedLines = textLines.map(line => ({ ...line, page: line.page + cumulativePageOffset }));
             allTextLines = [...allTextLines, ...shiftedLines];
             newDocuments.push({ id: crypto.randomUUID(), name: file.name, url: URL.createObjectURL(file), file: file, type: isExcel ? 'excel' : 'pdf', pageOffset: cumulativePageOffset, pageCount: pageCount });
             cumulativePageOffset += pageCount;
             await new Promise(r => setTimeout(r, 0));
        }
        setDocuments(newDocuments);
        if (newDocuments.length > 0) setActiveDocId(newDocuments[0].id);
        const combinedName = files[0].name + (files.length > 1 ? ` (+${files.length - 1} files)` : '');
        setLoadingMessage("Milling the lines into data...");
        setLoadingProgress(85);
        await new Promise(r => setTimeout(r, 50));
        await processText(allTextLines, combinedName, totalSize);
        setLoadingProgress(100);
        await new Promise(r => setTimeout(r, 200));
    } catch (error) { setStatus('error'); console.error(error); }
    finally { clearInterval(punInterval); clearInterval(progressInterval); }
  };

  const handleUpdateRow = (id: string, field: keyof ParsedLine, value: any) => {
      const sourceRow = data.find(r => r.id === id);
      if (!sourceRow) return;
      const isSpruceUpdate = field === 'spruceItemNo' || field === 'spruceDescription';
      const isClearing = isSpruceUpdate && !value; 
      setData(prev => {
          return prev.map(row => {
              const isTarget = row.id === id;
              const isSyncMatch = isSpruceUpdate && 
                                  row.item === sourceRow.item && 
                                  row.dimensions === sourceRow.dimensions && 
                                  row.grade === sourceRow.grade && 
                                  row.length === sourceRow.length;
              if (isTarget || isSyncMatch) {
                  let updated = { ...row };
                  if (field === 'section') updated.sectionLocked = true;
                  if (field === 'subSection') updated.subSectionLocked = true;
                  (updated as any)[field] = value;
                  if (isSpruceUpdate) {
                      updated.confidence = 1.0; 
                      if (isClearing) {
                          updated.spruceItemNo = "";
                          updated.spruceDescription = "";
                          updated.sprucePriceCents = null;
                          updated.spruceGroup = null;
                          updated.spruceSection = null;
                          updated.price = 0;
                          updated.spruceMapped = false;
                          updated.manuallyUnmapped = true;
                          updated.matchReason = "No match found, manually cleared by user.";
                      } else {
                          const match = catalog.find(p => p.itemNo === value || p.description === value);
                          if (match) {
                              const enrichedMatch = enrichCatalogProduct(match); 
                              const finalMapping = applyMappingToRow(updated, { ...enrichedMatch, source: 'MANUAL' });
                              updated = { ...updated, ...finalMapping };
                              updated.totalPrice = (updated.price || 0) * updated.total;

                              const memoryItem: MemoryItem = {
                                  lookupKey: buildLookupKey(updated.item, updated.dimensions),
                                  displayName: normalizeWhitespace(updated.item),
                                  dimensions: normalizeWhitespace(updated.dimensions),
                                  itemNo: match.itemNo,
                                  description: match.description
                              };
                              storageService.saveLearnedMapping(memoryItem).then(() => {
                                  storageService.getLearnedMappings().then(list => {
                                      const newMap = new Map<string, MemoryItem>();
                                      list.forEach(m => newMap.set(m.lookupKey, m));
                                      setLearnedMappings(newMap);
                                  });
                              });
                          } else {
                              updated.spruceMapped = false;
                              updated.manuallyUnmapped = false;
                              updated.matchReason = "Searching or custom code entry.";
                              if (field === 'spruceItemNo' && value.length >= 4) {
                                  const memoryItem: MemoryItem = {
                                      lookupKey: buildLookupKey(updated.item, updated.dimensions),
                                      displayName: normalizeWhitespace(updated.item),
                                      dimensions: normalizeWhitespace(updated.dimensions),
                                      itemNo: value,
                                      description: updated.spruceDescription || ''
                                  };
                                  storageService.saveLearnedMapping(memoryItem).then(() => {
                                      storageService.getLearnedMappings().then(list => {
                                          const newMap = new Map<string, MemoryItem>();
                                          list.forEach(m => newMap.set(m.lookupKey, m));
                                          setLearnedMappings(newMap);
                                      });
                                  });
                              }
                          }
                      }
                  } else if (field === 'qty' || field === 'length' || field === 'unit') {
                      if (updated.unit === 'L/M' || updated.unit === 'm2') updated.total = (updated.qty || 0) * (updated.length || 0);
                      else updated.total = updated.qty;
                      updated.totalPrice = (updated.price || 0) * updated.total;
                  } else if (field === 'price') {
                      updated.price = parseFloat(value) || 0;
                      updated.totalPrice = (updated.price || 0) * updated.total;
                  }
                  return updated;
              }
              return row;
          });
      });
  };

  const handleBulkUpdate = (ids: string[], field: keyof ParsedLine, value: any) => {
    setData(prev => {
        const idSet = new Set(ids);
        return prev.map(row => {
            if (idSet.has(row.id)) {
                let updated = { ...row };
                if (field === 'section') updated.sectionLocked = true;
                if (field === 'subSection') updated.subSectionLocked = true;
                (updated as any)[field] = value;
                if (field === 'qty' || field === 'length' || field === 'unit') {
                    if (updated.unit === 'L/M' || updated.unit === 'm2') updated.total = (updated.qty || 0) * (updated.length || 0);
                    else updated.total = updated.qty;
                    updated.totalPrice = (updated.price || 0) * updated.total;
                }
                if (field === 'spruceItemNo') {
                    updated.confidence = 1.0;
                    if (!value) {
                        updated.spruceDescription = "";
                        updated.spruceItemNo = "";
                        updated.sprucePriceCents = null;
                        updated.spruceGroup = null;
                        updated.spruceSection = null;
                        updated.price = 0;
                        updated.totalPrice = 0;
                        updated.spruceMapped = false;
                        updated.manuallyUnmapped = true;
                        updated.matchReason = "No match found, manually cleared by user.";
                    } else {
                        const match = catalog.find(p => p.itemNo === value);
                        if (match) { 
                            const enrichedMatch = enrichCatalogProduct(match);
                            const mappingUpdates = applyMappingToRow(updated, { ...enrichedMatch, source: 'MANUAL' });
                            updated = { ...updated, ...mappingUpdates };
                            updated.totalPrice = (updated.price || 0) * updated.total;
                        } else { 
                            updated.spruceMapped = false; 
                            updated.manuallyUnmapped = false;
                            updated.matchReason = "No exact match found, entering custom code.";
                        }
                    }
                }
                return updated;
            }
            return row;
        });
    });
  };

  const handleAddRow = (section?: string) => {
      const newLine: ParsedLine = {
          id: crypto.randomUUID(), category: 'Structural', section: section || data[0]?.section || 'New Section',
          subSection: 'Manual Add', item: 'New Item', dimensions: '', grade: '', qty: 1, length: null,
          unit: 'EA', total: 1, totalPrice: 0, originalLine: 'Manual Entry', confidence: 1.0, isNew: true,
          matchReason: "Manual entry, no catalog match attempted."
      };
      setData(prev => [newLine, ...prev]);
      activeRowIdSet(newLine.id);
  };

  const handleReloadJob = (item: HistoryItem) => {
      setData(item.data);
      setMetadata(item.metadata || null);
      setJobNotes(item.jobNotes || '');
      // Clear documents as blobs aren't stored in history JSON
      setDocuments([]);
      setActiveDocId(null);
      setStatus('ready');
      setCurrentView('table');
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setData([]);
      setDocuments([]);
      setCurrentView('upload');
      setSettings(DEFAULT_SETTINGS);
  };

  const handleResetView = () => {
      setUserAdjustedWidth(false);
  };

  const handleSaveColumnWidths = (widths: Record<string, number>) => {
      setSettings(prev => ({
          ...prev,
          tableColumnWidths: widths
      }));
      if (currentUser) {
          storageService.saveUserSettings(currentUser.id, {
              ...settings,
              tableColumnWidths: widths
          });
      }
  };

  if (!currentUser) {
      return <UserSplashScreen onSelectUser={setCurrentUser} logoUrl={settings.logoUrl} companyName={settings.companyName} />;
  }

  const isSidebarExpanded = isSidebarHovered || currentView === 'upload';
  const activeTheme = THEME_MAP[settings.themeColor] || THEME_MAP.blue;

  return (
    <div 
        className={`flex h-screen bg-slate-50 dark:bg-slate-955 transition-colors duration-300 font-sans text-slate-900 dark:text-slate-100 ${settings.darkMode ? 'dark' : ''}`}
        style={{ fontFamily: settings.fontFamily }}
    >
      <aside 
        className={`fixed lg:static inset-y-0 left-0 z-40 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-700 transition-[width] duration-200 ease-[cubic-bezier(0.2,0,0,1)] overflow-hidden will-change-[width] ${isSidebarExpanded ? 'lg:w-64' : 'lg:w-16'} translate-x-0 w-72 lg:translate-x-0`} 
        onMouseEnter={() => setIsSidebarHovered(true)} 
        onMouseLeave={() => setIsSidebarHovered(false)}
      >
        <div className="flex flex-col h-full items-start p-3">
          <div className={`flex items-center mb-8 h-8 transition-all duration-200 w-full ${isSidebarExpanded ? 'gap-3 px-1' : 'justify-center gap-0'}`}>
            <div className={`h-8 w-8 rounded flex-shrink-0 flex items-center justify-center text-white font-bold shadow-lg ${activeTheme.shadow} overflow-hidden bg-white ring-1 ring-slate-200`}>
              {settings.logoUrl ? (
                <img src={settings.logoUrl} alt="Logo" className="w-full h-full object-contain p-2" />
              ) : (
                <div className={`w-full h-full flex items-center justify-center ${activeTheme.bg} text-white`}>
                    {settings.companyName.charAt(0).toUpperCase()}
                </div>
              )}
            </div>
            <h1 className={`font-bold whitespace-nowrap transition-opacity duration-150 pointer-events-none overflow-hidden ${isSidebarExpanded ? 'opacity-100' : 'opacity-0'}`}>
              {settings.companyName}
            </h1>
          </div>
          <nav className="flex-1 space-y-1 w-full">
                {[
                    { id: 'upload', icon: <FileText size={18} />, label: 'Upload' },
                    { id: 'table', icon: <Table size={18} />, label: 'Takeoff Data' },
                    { id: 'history', icon: <History size={18} />, label: 'Job History' }
                ].map(nav => (
                    <button key={nav.id} onClick={() => setCurrentView(nav.id as ViewState)} className={`flex items-center rounded-lg transition-colors duration-200 group relative ${isSidebarExpanded ? 'w-full px-3 py-2 gap-3 h-10' : 'w-10 h-10 justify-center mx-auto'} ${currentView === nav.id ? `${activeTheme.bg} text-white shadow-md` : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800'}`} title={!isSidebarExpanded ? nav.label : undefined}>
                        <div className="flex-shrink-0 flex items-center justify-center w-5 h-5">{nav.icon}</div>
                        <span className={`font-medium text-sm whitespace-nowrap transition-[opacity,transform] duration-200 ${isSidebarExpanded ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-4 pointer-events-none absolute'}`}>{nav.label}</span>
                    </button>
                ))}
          </nav>
          <div className="w-full space-y-1 mt-auto pt-4 border-t border-slate-100 dark:border-slate-800">
            <button onClick={() => {setSettingsInitialTab('general'); setShowSettings(true);}} className={`flex items-center rounded-lg transition-colors duration-200 group relative ${isSidebarExpanded ? 'w-full px-3 py-2 gap-3 h-10' : 'w-10 h-10 justify-center mx-auto'} text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800`} title={!isSidebarExpanded ? "Settings" : undefined}>
                <div className="flex-shrink-0 flex items-center justify-center w-5 h-5"><Settings size={18} /></div>
                <span className={`text-sm whitespace-nowrap transition-[opacity,transform] duration-200 ${isSidebarExpanded ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-4 pointer-events-none absolute'}`}>Settings</span>
            </button>
            <button onClick={handleLogout} className={`flex items-center rounded-lg transition-colors duration-200 group relative ${isSidebarExpanded ? 'w-full px-3 py-2 gap-3 h-10' : 'w-10 h-10 justify-center mx-auto'} text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20`} title={!isSidebarExpanded ? "Log Out" : undefined}>
                <div className="flex-shrink-0 flex items-center justify-center w-5 h-5"><LogOut size={18} /></div>
                <span className={`text-sm whitespace-nowrap transition-[opacity,transform] duration-200 ${isSidebarExpanded ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-4 pointer-events-none absolute'}`}>Log Out</span>
            </button>
            <div className={`mt-2 p-2 rounded-xl bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 flex items-center transition-all group/profile ${isSidebarExpanded ? 'gap-3' : 'justify-center'}`}>
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold shrink-0 overflow-hidden ${currentUser.role === 'admin' ? 'bg-amber-100 text-amber-600 ring-1 ring-amber-500/20' : 'bg-blue-100 text-blue-600 ring-1 ring-blue-500/20'}`}>
                    {currentUser.avatar ? <img src={currentUser.avatar} alt={currentUser.name} className="w-full h-full object-cover" /> : currentUser.name.charAt(0)}
                </div>
                {isSidebarExpanded && (
                    <div className="min-w-0 flex-1">
                        <p className="text-xs font-bold truncate text-slate-700 dark:text-slate-200">{currentUser.name}</p>
                        <p className={`text-[10px] uppercase font-black tracking-tighter ${currentUser.role === 'admin' ? 'text-amber-500' : 'text-blue-500'}`}>{currentUser.role}</p>
                    </div>
                )}
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
        <div className="flex-1 overflow-hidden p-4 bg-slate-50 dark:bg-slate-955">
           {currentView === 'upload' && (
             <div className="h-full flex items-center justify-center">
               <div className="w-full max-w-3xl animate-enter">
                 <FileUpload onFileUpload={handleFileUpload} status={status} activeProfile={activeProfile} onProfileChange={setActiveProfile} onManageProfiles={() => {setSettingsInitialTab('profiles'); setShowSettings(true);}} progress={loadingProgress} customMessage={loadingMessage}/>
               </div>
             </div>
           )}
           {currentView === 'table' && (
               <div className="flex flex-col h-full gap-2 animate-fade-in">
                   <div ref={headerContainerRef} className="grid grid-cols-1 xl:grid-cols-[minmax(320px,520px)_auto_1fr] gap-3 items-stretch shrink-0 mb-1">
                       {metadata && <JobHeader metadata={metadata} onUpdate={setMetadata} />}
                       {uiPrefs.showHeaderMetrics ? (
                           <StatsCards stats={stats} pineWastageSummary={pineWastageSummary} />
                       ) : <div />}
                       {uiPrefs.showJobNotes ? (
                           <JobNotesCard notes={jobNotes} onUpdateNotes={setJobNotes} />
                       ) : <div />}
                   </div>
                   <div className="flex-1 flex min-h-0 relative" ref={splitContainerRef}>
                       {documents.length > 0 && activeDocContext && uiPrefs.showPdfPreview && (
                           <>
                               <div className={`hidden xl:flex flex-col h-full min-h-0 overflow-hidden ${!isResizing ? 'transition-all duration-500 ease-in-out' : ''}`} style={{ width: `${leftPanelWidth}%` }}>
                                   {activeDocContext.doc.type === 'excel' ? <ExcelViewer fileUrl={activeDocContext.doc.url} documents={documents} activeDocumentId={activeDocId!} onDocumentChange={setActiveDocId} highlightPage={activeDocContext.highlightPage} highlightRect={activeDocContext.highlightRect} /> : <PdfViewer fileUrl={activeDocContext.doc.url} highlightPage={activeDocContext.highlightPage} highlightRect={activeDocContext.highlightRect} documents={documents} activeDocumentId={activeDocId!} onDocumentChange={setActiveDocId} />}
                               </div>
                               <div 
                                    className="w-1.5 hover:w-2 bg-slate-200 dark:bg-slate-800 hover:bg-blue-500 dark:hover:bg-blue-500 cursor-col-resize transition-all self-stretch group flex items-center justify-center z-10"
                                    onMouseDown={(e) => { e.preventDefault(); setIsResizing(true); }}
                                >
                                    <div className="w-0.5 h-12 bg-slate-400 dark:bg-slate-600 rounded-full group-hover:bg-white"></div>
                                </div>
                           </>
                       )}
                       <div className={`flex-1 flex flex-col min-h-0 min-w-0 ${documents.length > 0 && uiPrefs.showPdfPreview ? 'pl-1' : ''}`}>
                            <PreviewTable 
                                allData={data}
                                data={data} 
                                onUpdateRow={handleUpdateRow} 
                                onBulkUpdate={handleBulkUpdate} 
                                onBulkDelete={(ids) => setData(prev => prev.filter(r => !ids.includes(r.id)))} 
                                onDeleteRow={(id) => setData(prev => prev.filter(r => r.id !== id))} 
                                onAddRow={handleAddRow} 
                                activeRowId={activeRowId} 
                                onRowClick={activeRowIdSet} 
                                catalog={catalog} 
                                onExport={() => setShowExport(true)} 
                                onInspect={setInspectRow} 
                                uiPreferences={uiPrefs} 
                                onResetView={handleResetView}
                                onTotalWidthReport={handleTotalTableWidthReport}
                                pineWastagePct={pineWastageSummary?.overallWastagePct}
                                savedColumnWidths={settings.tableColumnWidths}
                                onSaveColumnWidths={handleSaveColumnWidths}
                                onReparse={handleReparse}
                                isReparsing={status === 'parsing'}
                            />
                       </div>
                   </div>
               </div>
           )}
           {currentView === 'history' && <HistoryView history={history} onRefresh={() => storageService.getAll(currentUser.id).then(setHistory)} onReloadJob={handleReloadJob} />}
        </div>
        <SettingsModal isOpen={showSettings} onClose={() => setShowSettings(false)} settings={settings} onUpdateSettings={setSettings} onUserUpdate={setCurrentUser} initialTab={settingsInitialTab} activeProfileId={activeProfile.id} currentUser={currentUser} />
        <ExportModal isOpen={showExport} onClose={() => setShowExport(false)} data={data} filename={metadata?.name} onManageTemplates={() => {setShowExport(false); setSettingsInitialTab('templates'); setShowSettings(true);}} metadata={metadata} history={history} jobNotes={jobNotes} />
        {inspectRow && <ParsingInspector isOpen={!!inspectRow} onClose={() => setInspectRow(null)} row={inspectRow} />}
      </main>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { HistoryItem } from '../types';
import { FileDown, Trash2, Calendar, FileText, Package, Clock, Building2, Phone, MapPin, Search, Tag, Pin, PinOff, Upload, Download, Filter, MoreHorizontal, CheckSquare, Square, FileDiff, NotebookPen, Save, X, Mail, Ruler, Layers, Eye, Maximize2 } from 'lucide-react';
import { exportToCsv } from '../services/excelService';
import { storageService } from '../services/storage';
import { ComparisonView } from './ComparisonView';

interface HistoryViewProps {
  history: HistoryItem[];
  onRefresh: () => void;
  onReloadJob?: (item: HistoryItem) => void;
}

export const HistoryView: React.FC<HistoryViewProps> = ({ history, onRefresh, onReloadJob }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItems, setSelectedItems] = useState<Set<string>>(new Set());
  const [tagInput, setTagInput] = useState<{id: string, value: string} | null>(null);

  // UI State for Notes Modal
  const [editingNoteId, setEditingNoteId] = useState<string | null>(null);
  const [tempNote, setTempNote] = useState('');

  // UI State for Comparison
  const [comparisonItems, setComparisonItems] = useState<[HistoryItem, HistoryItem] | null>(null);

  // Filter Logic
  const filteredHistory = useMemo(() => {
    if (!searchTerm) return history;
    const lower = searchTerm.toLowerCase();
    return history.filter(item => {
      const builder = item.metadata?.builder?.toLowerCase() || '';
      const address = item.metadata?.address?.toLowerCase() || '';
      const filename = item.fileName.toLowerCase();
      const tags = item.tags?.join(' ').toLowerCase() || '';
      const email = item.metadata?.email?.toLowerCase() || '';
      const phone = item.metadata?.phoneNumber?.toLowerCase() || '';

      return builder.includes(lower) || 
             address.includes(lower) || 
             filename.includes(lower) ||
             tags.includes(lower) ||
             email.includes(lower) ||
             phone.includes(lower);
    });
  }, [history, searchTerm]);

  // Bulk Actions
  const toggleSelection = (id: string) => {
    const newSet = new Set(selectedItems);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedItems(newSet);
  };

  const selectAll = () => {
    if (selectedItems.size === filteredHistory.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(filteredHistory.map(h => h.id)));
    }
  };

  const handleBulkDelete = async () => {
    if (!confirm(`Are you sure you want to delete ${selectedItems.size} items?`)) return;
    for (const id of selectedItems) {
      await storageService.delete(id);
    }
    setSelectedItems(new Set());
    onRefresh();
  };

  const handleBulkExport = () => {
    const itemsToExport = history.filter(h => selectedItems.has(h.id));
    itemsToExport.forEach(item => {
        const name = item.metadata?.name || item.fileName;
        exportToCsv(item.data, name);
    });
    setSelectedItems(new Set());
  };

  const handleCompare = () => {
      if (selectedItems.size !== 2) return;
      const items = history.filter(h => selectedItems.has(h.id));
      if (items.length === 2) {
          // Sort by timestamp so Oldest is A, Newest is B
          items.sort((a, b) => a.timestamp - b.timestamp);
          setComparisonItems([items[0], items[1]]);
      }
  };

  // Individual Actions
  const handleDownload = (item: HistoryItem) => {
    const name = item.metadata?.name || item.fileName;
    exportToCsv(item.data, name);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Delete this takeoff?")) {
        await storageService.delete(id);
        onRefresh();
    }
  };

  const handleTogglePin = async (id: string) => {
    await storageService.togglePin(id);
    onRefresh();
  };

  const handleAddTag = async (e: React.KeyboardEvent, id: string) => {
    if (e.key === 'Enter' && tagInput && tagInput.value.trim()) {
        const item = history.find(h => h.id === id);
        if (item) {
            const currentTags = item.tags || [];
            if (!currentTags.includes(tagInput.value.trim())) {
                const newTags = [...currentTags, tagInput.value.trim()];
                await storageService.updateTags(id, newTags);
                onRefresh();
            }
        }
        setTagInput(null);
    }
  };

  // Backup/Restore
  const handleExportBackup = async () => {
    const json = await storageService.exportBackup();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `timber_takeoff_backup_${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleImportBackup = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = async (ev) => {
            const content = ev.target?.result as string;
            try {
                const count = await storageService.importBackup(content);
                alert(`Successfully restored ${count} items.`);
                onRefresh();
            } catch (err) {
                alert("Failed to import backup. Invalid file format.");
            }
        };
        reader.readAsText(file);
    }
  };

  // Notes Modal Logic
  const openNoteEditor = (item: HistoryItem) => {
      setEditingNoteId(item.id);
      setTempNote(item.jobNotes || '');
  };

  const saveNote = async () => {
      if (!editingNoteId) return;
      // We need to update the item in DB. We can use `add` (put) to overwrite.
      const item = history.find(h => h.id === editingNoteId);
      if (item) {
          const updated = { ...item, jobNotes: tempNote };
          await storageService.add(updated);
          onRefresh();
      }
      setEditingNoteId(null);
  };

  if (comparisonItems) {
      return <ComparisonView itemA={comparisonItems[0]} itemB={comparisonItems[1]} onClose={() => setComparisonItems(null)} />;
  }

  return (
    <div className="flex flex-col gap-6 animate-fade-in relative">

      {/* Note Editor Modal */}
      {editingNoteId && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
              <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-300 dark:border-slate-700">
                  <div className="p-4 border-b border-slate-300 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
                      <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                          <NotebookPen size={18} /> Job Notes
                      </h3>
                      <button onClick={() => setEditingNoteId(null)}><X size={20} className="text-slate-400 hover:text-red-500" /></button>
                  </div>
                  <div className="p-4">
                      <textarea 
                        className="w-full h-48 p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                        placeholder="Add notes about this job, delivery instructions, etc..."
                        value={tempNote}
                        onChange={(e) => setTempNote(e.target.value)}
                      />
                  </div>
                  <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-t border-slate-300 dark:border-slate-700 flex justify-end gap-2">
                      <button onClick={saveNote} className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold flex items-center gap-2">
                          <Save size={16} /> Save Note
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Control Bar */}
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-300 dark:border-slate-700 p-4 flex flex-col md:flex-row gap-4 justify-between items-center">

        {/* Search */}
        <div className="relative w-full md:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
                type="text" 
                placeholder="Search clients, addresses, tags..." 
                className="w-full pl-10 pr-4 py-2 rounded-lg bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 focus:ring-2 focus:ring-blue-500 outline-none text-slate-800 dark:text-slate-200 transition-colors shadow-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
        </div>

        {/* Action Buttons */}
        <div className="flex items-center gap-3 w-full md:w-auto justify-end">
            <label className="cursor-pointer px-4 py-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-700 dark:hover:bg-slate-600 rounded-lg text-slate-600 dark:text-slate-300 font-medium text-sm flex items-center gap-2 transition-colors">
                <Upload size={16} />
                <span className="hidden sm:inline">Restore</span>
                <input type="file" accept=".json" onChange={handleImportBackup} className="hidden" />
            </label>
            <button 
                onClick={handleExportBackup}
                className="px-4 py-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-700 dark:hover:bg-slate-600 rounded-lg text-slate-600 dark:text-slate-300 font-medium text-sm flex items-center gap-2 transition-colors"
            >
                <Download size={16} />
                <span className="hidden sm:inline">Backup</span>
            </button>
        </div>
      </div>

      {/* Bulk Actions Bar */}
      {selectedItems.size > 0 && (
          <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-xl p-3 flex items-center justify-between animate-fade-in sticky top-0 z-20 shadow-md backdrop-blur-md">
              <span className="text-blue-700 dark:text-blue-300 font-medium text-sm ml-2">
                  {selectedItems.size} items selected
              </span>
              <div className="flex gap-2">
                  {selectedItems.size === 2 && (
                      <button 
                        onClick={handleCompare}
                        className="px-4 py-1.5 bg-violet-600 hover:bg-violet-700 text-white rounded-md text-sm shadow-sm flex items-center gap-2"
                      >
                          <FileDiff size={16} /> Compare Versions
                      </button>
                  )}
                  <button onClick={handleBulkExport} className="px-3 py-1.5 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-md text-sm shadow-sm hover:text-blue-600 border border-slate-200 dark:border-slate-700">Export</button>
                  <button onClick={handleBulkDelete} className="px-3 py-1.5 bg-red-600 text-white rounded-md text-sm shadow-sm hover:bg-red-700">Delete</button>
              </div>
          </div>
      )}

      {/* List */}
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-300 dark:border-slate-700 overflow-hidden">
        {filteredHistory.length === 0 ? (
             <div className="p-12 text-center text-slate-500 dark:text-slate-400">
                 {searchTerm ? 'No results matching your search.' : 'No history found.'}
             </div>
        ) : (
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-600 dark:text-slate-300 font-semibold border-b border-slate-300 dark:border-slate-700">
            <tr>
              <th className="w-12 px-4 py-4">
                  <button onClick={selectAll} className="text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200">
                    {selectedItems.size === filteredHistory.length && filteredHistory.length > 0 ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
              </th>
              <th className="px-4 py-4 min-w-[120px]">Date</th>
              <th className="px-4 py-4 min-w-[200px]">Job Details</th>
              <th className="px-4 py-4 min-w-[200px]">Site Address</th>
              <th className="px-4 py-4 text-center">Items</th>
              <th className="px-4 py-4 text-center">Total LM</th>
              <th className="px-4 py-4 text-center">Sections</th>
              <th className="px-4 py-4">Tags</th>
              <th className="px-4 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
            {filteredHistory.map((item) => {
               const builder = item.metadata?.builder;
               const address = item.metadata?.address;
               const email = item.metadata?.email;
               const phone = item.metadata?.phoneNumber;
               const isSelected = selectedItems.has(item.id);

               // Calculate extended metrics
               const totalLm = item.data.filter(d => d.unit === 'L/M').reduce((acc, curr) => acc + (curr.total || 0), 0);
               const uniqueSections = new Set(item.data.map(d => d.section)).size;

               return (
                <tr key={item.id} className={`hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors ${item.isPinned ? 'bg-amber-50/50 dark:bg-amber-900/10' : ''}`}>
                  {/* Select */}
                  <td className="px-4 py-4 align-top">
                      <button onClick={() => toggleSelection(item.id)} className={`transition-colors ${isSelected ? 'text-blue-500' : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'}`}>
                          {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                      </button>
                  </td>

                  {/* Date & Pin */}
                  <td className="px-4 py-4 align-top">
                    <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2">
                            <button onClick={() => handleTogglePin(item.id)} className={`${item.isPinned ? 'text-amber-500' : 'text-slate-300 dark:text-slate-600 hover:text-slate-400'}`}>
                                {item.isPinned ? <Pin size={14} fill="currentColor" /> : <Pin size={14} />}
                            </button>
                            <span className="font-medium text-slate-700 dark:text-slate-200">{new Date(item.timestamp).toLocaleDateString()}</span>
                        </div>
                        <span className="text-xs text-slate-400 dark:text-slate-500 pl-6">{new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                  </td>

                  {/* Job Details */}
                  <td 
                    className="px-4 py-4 align-top cursor-pointer group/details" 
                    onClick={() => onReloadJob?.(item)}
                    title="Click to open this job"
                  >
                    <div className="flex flex-col gap-1">
                        <div className="flex items-start gap-2 font-medium text-slate-800 dark:text-slate-100 group-hover/details:text-blue-600 dark:group-hover/details:text-blue-400 transition-colors">
                             <FileText size={16} className="text-blue-500 mt-0.5 flex-shrink-0" />
                             <span className="break-words line-clamp-2" title={item.fileName}>{item.fileName}</span>
                        </div>
                        {builder && (
                            <div className="flex items-center gap-2 text-xs text-violet-600 dark:text-violet-300 pl-6">
                                <Building2 size={12} />
                                <span>{builder}</span>
                            </div>
                        )}
                        {email && (
                            <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400 pl-6">
                                <Mail size={12} />
                                <span className="truncate max-w-[150px]">{email}</span>
                            </div>
                        )}
                        {phone && (
                            <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400 pl-6">
                                <Phone size={12} />
                                <span>{phone}</span>
                            </div>
                        )}
                    </div>
                  </td>

                  {/* Address */}
                  <td className="px-4 py-4 align-top">
                    {address ? (
                        <div className="flex items-start gap-2 text-slate-600 dark:text-slate-300 text-sm">
                            <MapPin size={16} className="text-red-500 mt-0.5 flex-shrink-0" />
                            <span className="break-words line-clamp-2" title={address}>{address}</span>
                        </div>
                    ) : (
                        <span className="text-slate-300 dark:text-slate-600 italic pl-6 text-xs">No address</span>
                    )}
                  </td>

                  {/* Items */}
                  <td className="px-4 py-4 text-center align-top">
                    <div className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-200 text-xs font-medium">
                      <Package size={12} />
                      {item.itemCount}
                    </div>
                  </td>

                  {/* Total LM */}
                  <td className="px-4 py-4 text-center align-top">
                    <div className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-300 text-xs font-bold border border-emerald-100 dark:border-emerald-800">
                      <Ruler size={12} />
                      {totalLm.toFixed(1)}m
                    </div>
                  </td>

                  {/* Sections */}
                  <td className="px-4 py-4 text-center align-top">
                    <div className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-violet-50 dark:bg-violet-900/30 text-violet-600 dark:text-violet-300 text-xs font-bold border border-violet-100 dark:border-violet-800">
                      <Layers size={12} />
                      {uniqueSections}
                    </div>
                  </td>

                  {/* Tags */}
                  <td className="px-4 py-4 align-top">
                      <div className="flex flex-wrap gap-1">
                          {item.tags?.map(tag => (
                              <span key={tag} className="px-2 py-0.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-300 text-xs rounded border border-blue-100 dark:border-blue-800 flex items-center gap-1 group">
                                  {tag}
                                  <button 
                                    onClick={() => {
                                        const newTags = item.tags?.filter(t => t !== tag) || [];
                                        storageService.updateTags(item.id, newTags).then(onRefresh);
                                    }}
                                    className="hidden group-hover:block hover:text-red-500"
                                  >
                                      &times;
                                  </button>
                              </span>
                          ))}
                          {tagInput?.id === item.id ? (
                              <input 
                                autoFocus
                                type="text" 
                                className="w-20 px-1 py-0.5 text-xs border rounded bg-white border-slate-300 text-slate-800 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                placeholder="Enter..."
                                onBlur={() => setTagInput(null)}
                                onKeyDown={(e) => handleAddTag(e, item.id)}
                                onChange={(e) => setTagInput({ id: item.id, value: e.target.value })}
                              />
                          ) : (
                              <button 
                                onClick={() => setTagInput({ id: item.id, value: '' })}
                                className="px-1.5 py-0.5 text-slate-400 hover:text-blue-500 border border-dashed border-slate-300 dark:border-slate-600 rounded hover:border-blue-300 dark:hover:border-blue-500 text-xs"
                              >
                                  +
                              </button>
                          )}
                      </div>
                  </td>

                  {/* Actions */}
                  <td className="px-4 py-4 text-right whitespace-nowrap align-top">
                    <div className="flex items-center justify-end gap-2">
                      <button
                        onClick={() => onReloadJob?.(item)}
                        className="text-blue-600 hover:text-blue-700 dark:hover:text-blue-400 p-2 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-colors"
                        title="Open Job in Takeoff Table"
                      >
                         <Maximize2 size={16} />
                      </button>
                      <button
                        onClick={() => openNoteEditor(item)}
                        className="text-amber-500 hover:text-amber-600 dark:hover:text-amber-400 p-2 rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/20 transition-colors"
                        title="Job Notes"
                      >
                         <NotebookPen size={16} />
                      </button>
                      <button
                        onClick={() => handleDownload(item)}
                        className="text-green-600 dark:text-green-500 hover:text-green-700 dark:hover:text-green-400 font-medium text-sm flex items-center gap-1.5 px-3 py-1.5 rounded-lg hover:bg-green-50 dark:hover:bg-green-900/20 transition-colors"
                        title="Download CSV"
                      >
                        <FileDown size={16} />
                      </button>
                      <button
                        onClick={() => handleDelete(item.id)}
                        className="text-slate-400 hover:text-red-500 dark:hover:text-red-400 p-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                        title="Delete"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        )}
      </div>
    </div>
  );
};
